"""
Parameterized generator for GH736_AQUA_2170.

Source PR:    https://github.com/DestinE-Climate-DT/AQUA/pull/2170
Source Issue: https://github.com/DestinE-Climate-DT/AQUA/issues/2168

Seed varies: renames 'abs_rel' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH736_AQUA_2170'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH736_AQUA_2170'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('abs_rel', 'abs_rel' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH736_AQUA_2170',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'DestinE-Climate-DT/AQUA',
                "pr_number": 2170,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/DestinE-Climate-DT/AQUA/pull/2170",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'CHANGELOG.md': '# Changelog\n\nAll notable changes to this project will be documented in this file.\nThe format is based on [Keep a Changelog](https://keepachangelog.com/en/1.1.0/)\n\n## [Unreleased]\n\nUnreleased in the current development version (target v0.18.0):\nRemoved:\n-  removed old OutputSaver (#2146) \n\nWorkflow modifications:\n- `aqua-analysis.py` is now an entry point `aqua analysis` in the AQUA console, with the same syntax as before.\n\nAQUA core complete list:\n- Hotfix in catgen for monthly chunking (#2184)\n- Fix loaded areas as dataset (#2174)\n- Few graphical adjustments in multiple_maps (#2159)\n- Fix fldstat coordinate treatment (#2147)\n- Fixer applied when units name changes is required and no factor is found (#2128)\n- Update aqua-analysis config for refactored diagnostics (#2144)\n- Fixed incompatible coordinate transformatiosn (#2137)\n- Added Nord4 support in the `load-aqua-container.sh` script (#2130)\n- Add `aqua analysis` to replace the `aqua-analysis.py` script, with a more flexible CLI interface (#2065)\n- Bugfix in `plot_seasonalcycles()` trying to use a non-existing `time` coordinate (#2114)\n- Add `norm` keyword argument to the `plot_single_map` to allow non-linear colorbar normalisation (#2107)\n- `draw_manual_gridlines()` utility function to draw gridlines on cartopy maps (#2105)\n- `apply_circular_window()` utility function to apply a circular window to cartopy maps (#2100)\n\nAQUA diagnostics complete list:\n- Boxplots: add support for reader_kwargs (#2149)\n- Global Biases: add the `diagnostic_name` option in config file (#2159)\n- Gregory: refined the reference label generation (#2157)\n- Seaice: add support for `reader_kwargs` (#2153)\n- Remove old seaice diagnostic scripts (#2152)\n- Timeseries: fix lazy calculation of seasonal cycles (#2143)\n- Boxplots: fix output dir (#2136) \n- Boxplots: add tests and update docs (#2129)\n- Seaice: refactored `seaice` diagnostic with cli, relative `config_seaice.yaml` and `regions_definition.yaml` files. Add updated tests for the diagnostic. Introduce bias plot with custom projections. Extend some graphics functions features (e.g. `add_land` in `single_map.py` or fig,ax definition of `plot_seasonalcycle`  in `timeseries.py`). Enhance utils functions (e.g. `set_map_title`; add `merge_attrs` in `sci_util.py`). Add `int_month_name` in `time.py` and `strlist_to_phrase` for grammar-consistent descriptions (#1684, #2140, #2165, #2178)\n- Stratification: Stratification class to create density and mixed layer depth data, notebook and tests added. (#2093)\n- Radiation: complete refactor of the diagnostic, now based on the `Boxplots` diagnostic and the  `boxplot ` function in graphics (#2007)\n- SeasonalCycles: fix a bug which was preventing to plot when no reference data is provided (#2114)\n\n## [v0.17.0]\n\nMain changes are:\n1. Support for realizations for `aqua-analysis`, `aqua-push` and a set of diagnostics (Timeseries, Global Biases, Teleconnections, Ecmean)\n2. Support for data-portfolio v2.0.0\n3. LRA output tree refactored accomodating for realization, statistic and frequency\n\nRemoved:\n-  removed Reader.info() method (#2076) \n\nWorkflow modifications:\n- `machine` and `author` are mandatory fields in the catalog generator config file.\n- Data portfolio required is v2.0.0, no API changes are involved in this change.\n- Add possibility to change the \'default\' realization in Catalog Generator config file.\n- AQUA analysis can take a `--realization` option to enable the analysis of a specific realization.\n\nAQUA core complete list:\n- Introduce a tentative command to generate grids from sources, `aqua grids build` based on `GridBuilder` class (#2066)\n- Support for data-portfolio v2.0.0: updated catalog generator, pinned gsv to v2.12.0. Machine now required in config. (#2092)\n- Add possibility to change the \'default\' realization in Catalog Generator config file (#2058) \n- `aqua add <catalog>` option in the AQUA console can use GITHUB_TOKEN and GITHUB_USER environment variables to authenticate with GitHub API (#2081)\n- Added a `aqua update -c all` option in the AQUA console to update all the catalogs intalled from the Climate-DT repository (#2081)\n- `Reader` can filter kwargs so that a parameter not available in the intake source is removed and not passed to the intake driver (#2074)\n- Adapt catgen to changes in data-portfolio v1.3.2 (#2076)\n- Add `get_projection()` utility function for selection of Cartopy map projections (#2068)\n- Tools to push to dashboard support ensemble realizations (#2070)\n- `aqua-analysis.py` now supports a `--realization` option to enable the analysis of a specific realization (#2041, #2090)\n- Separate new histogram function in the framework (#2061)\n- Introducing `timsum()` method to compute cumulative sum (#2059)\n- `EvaluateFormula` class to replace the `eval_formula` function with extra provenance features (#2042)\n- Solve fixer issue leading to wrong target variable names (#2057)\n- Upgrade to `smmregrid=0.1.2`, which fixes coastal erosion in conservative regridding (#1963)\n- Refactor LRA of output and catalog entry creatro with `OutputPathBuilder` and `CatalogEntryBuilder` classes (#1932)\n- LRA cli support realization, stat and frequency (#1932)\n- Update to the new STACv2 API for Lumi (#2039)\n- `aqua add` and `aqua avail` commands now support a `--repository` option to specify a different repository to explore (#2037)\n- `AQUA_CONFIG` environment variable can be set to customize the path of the configuration files in `aqua-analysis.py` (#2027)\n- Development base container updated to stack 7.0.2.8 (#2022, #2025)\n- `Trender()` class provide also coefficients and normalize them (#1991)\n- Catalog entry builder functionality for diagnostics included in OutputSaver Class (#2086)\n\nAQUA diagnostics complete list:\n- Sea-ice extent and volume: bugs related to use of legacy reader functionality (#2111)\n- Ocean Trends: Trends class to create trend data along with zonal trend, notebook and tests added. (#1990)\n- Global Biases: allow GlobalBias to take projection as argument (#2036)\n- ECmean: diagnostics refactored to use `OutputSaver` and new common configuration file (#2012)\n- ECmean: dependency to 0.1.15 (#2012)\n- Timeseries, Global Biases, Teleconnections, Ecmean: `--realization` option to select a specific realization in the CLI (#2041)\n- Global Biases: add try-except block in cli (#2069)\n- Global Biases: handling of formulae and Cloud Radiative Forcing Computation (#2031)\n- Global Biases: pressure levels plot works correctly with the CLI (#2027)\n- Timeseries: `diagnostic_name` option to override the default name in the CLI (#2027)\n- Global Biases: output directory is now correctly set in the cli (#2027)\n- Timeseries: `center_time` option to center the time axis is exposed in the CLI (#2028)\n- Timeseries: fix the missing variable name in some netcdf output (#2023)\n- Diagnostic core: new `_select_region` method in `Diagnostic`, wrapped by `select_region` to select a region also on custom datasets (#2020, #2032)\n\n## [v0.16.0]\n\nRemoved:\n- Removed source or experiment specific fixes; only the `fixer_name` is now supported.\n\nWorkflow modifications:\n- Due to a bug in Singularity, `--no-mount /etc/localtime` has to be implemented into the AQUA container call \n- `push_analysis.sh` now updates and pushes to LUMI-O the file `experiments.yaml`, which is used by the \n  dashboard to know which experiments to list. The file is downloaded from the object store, updated and \n  pushed back. Additionally it exit with different error codes if the bucket is missing or the S3 credential\n  are not correct.\n\nAQUA core complete list:\n- Update to the new STAC API for Lumi (#2017)\n- Added the `aqua grids set` command to set the paths block in the `aqua-config.yaml` file, overwriting the default values (#2003)\n- Derivation of metadata from eccodes is done with a builtin python method instead of definiton file inspection (#2009, #2014)\n- `h5py` installed from pypi. Hard pin to version 3.12.1 removed in favor of a lower limit to the version (#2002)\n- `aqua-analysis` can accept a `--regrid` argument in order to activate the regrid on each diagnostics supporting it (#1947)\n- `--no-mount /etc/localtime` option added to the `load_aqua_container.sh` script for all HPC (#1975)\n- Upgrade to eccodes==2.41.0 (#1890)\n- Fix HPC2020 (ECMWF) installation (#1994)\n- `plot_timeseries` can handle multiple references and ensemble mean and std (#1988, #1999)\n- Support for CDO 2.5.0, modified test files accordingly (v6) (#1987)\n- Remove DOCKER secrets and prepare ground for dependabot action e.g introduce AQUA_GITHUB_PAT (#1983)\n- `Trender()` class to include both `trend()` and `detrend()` method (#1980)\n- `cartopy_offlinedata` is added on container and path is set in cli call, to support MN5 no internet for coastlines download (#1960)\n- plot_single_map() can now handle high nlevels with a decreased cbar ticks density (#1940)\n- plot_single_map() now can avoid coastlines to support paleoclimate maps (#1940)\n- Fixes to support EC-EARTH4 conversion to GRIB2 (#1940)\n- Added support for TL63, TL255, eORCA1, ORCA2 grids for EC-EARTH4 model (#1940)\n- `FldStat()` as independent module for area-weighted operations (#1835)\n- Refactor of `Fixer()`, now independent from the `Reader()` and supported by classes `FixerDataModel` and `FixerOperator` (#1929) \n- Update and push to lumi-o the a file listing experiments needed by the dashboard (#1950)\n- Integration of HEALPix data with `plot_single_map()` (#1897)\n- Use scientific notation in multiple maps plotting to avoid label overlapping (#1953)\n\nAQUA diagnostics complete list:\n- Diagnostic core: a `diagnostic_name` is now available in the configuration file to override the default name (#2000)\n- Ecmean, GlobalBiases, Teleconnections: regrid functionality correctly working in cli (#2006)\n- Diagnostic core: updated docs for `OutputSaver` (#2010)\n- Diagnostic core: save_netcdf() is now based on the new OutputSaver (#1965)\n- Diagnostic core: raise an error if retrieve() returns an empty dataset (#1997)\n- GlobalBiases: major refactor (#1803, #1993)\n- Ocean Drift: using the `_set_region` method from the `Diagnostic` class (#1981)\n- Diagnostic core: new `_set_region` method in `Diagnostic` class to find region name, lon and lat limits (#1979)\n- Timeseries: regions are now in the `definitions` folder (not `interface` anymore) (#1884)\n- Teleconnections: complete refactor according to the Diagnostic, PlotDiagnostic schema (#1884)\n- Radiations: timeseries correctly working for exps with enddate before 2000 (#1940)\n- Diagnostic core: new `round_startdate` and `round_enddate` functions for time management (#1940)\n- Timeseries: fix in the new cli wich was ignoring the regrid option and had bad time handling (#1940)\n- Timeseries: Use new OutputSaver in Timeseries diagnostics (#1948, #2000)\n- Diagnostic core: new `select_region` to crop a region based on `_set_region` and `area_selection` method (#1984)\n\n## [v0.15.0]\n\nMain changes are:\n- Polytope support \n- Plotting routines support cartopy projections and matplotlib styles\n- Major refactor of AQUA core functionalities: Regridder, Datamodel, OutputSaver, Timstat  \n- Major refactor of Timeseries, SeasonalCycle, GregoryPlot diagnostics\n\nRemoved:\n- `aqua.slurm` has been removed.\n\nWorkflow modifications:\n- `push_analysis.sh` (and the tool `push_s3.py` which it calls) now both return proper error codes if the transfer fails. 0 = ok, 1 = credentials not valid, 2 = bucket not found. This would allow the workflow to check return codes. As an alternative, connectivity could be tested before attempting to run push_analysis by pushing a small file (e.g. with `python push_s3.py aqua-web ping.txt`))\n\nAQUA core complete list:\n- Add FDB_HOME to debug logs (#1914)\n- Enabling support for DestinE STAC API to detect `bridge_start_date`and `bridge_end_date` (#1895)\n- Return codes for push_s3 and push_analysis utilities (#1903)\n- Polytope support (#1893)\n- Additional stats for LRA and other refinements (#1886) \n- New OutputSaver class (#1837)\n- Introduce a `Timstat()` module independent from the `Reader()` (#1832)\n- Adapt Catalog Generator to Data-Portfolio v1.3.0 (#1848)\n- Introduction of a internal AQUA data model able to guess coordinates and convert toward required target data convention definition (#1862, #1877, #1883)\n- Custom `paths` in the `config-aqua.yaml` can now be defined and will take priority over the catalog paths (#1809)\n- Remove deprecated `aqua.slurm` module (#1860)\n- Refactor of `plot_maps()` and `plot_maps_diff()` functions with projection support and use their single map version internally (#1865)\n- Refactor of `plot_single_map()` and `plot_single_map_diff()` functions with projection support (#1854)\n- Refactor time handling: replacement of `datetime` objects and of `pd.Timestamp` lists (#1828)\n- Fix the `regrid_method` option in the Reader (#1859)\n- Add a GitHub Token for downloading ClimateDT catalogs (#1855)\n- Ignore `nonlocal` complaints by flake8 (#1855)\n- WOCE-ARGO ocean dataset grids and fixes added (#1846)\n- Upgrade of base container to FDB 5.15.11 (#1845)\n- Matplotlib styles can be set in the configuration file (#1729)\n- Graphics refactoring for timeseries plot functions (#1729, #1841)\n- Major refactor of the regrid options, with new modular `Regridder()` class replacing `Regrid()` mixin (#1768)\n- Refactor of the `retrieve_plain()` function with contextmanager and smmregrid GridInspector (#1768)\n\nAQUA diagnostics complete list:\n- Diagnostic core: refinement of OutputSaver metadata and name handling (#1901)\n- Diagnostic core: refactor of the documentation folder structure (#1891)\n- Timeseries: complete refactor of the timeseries diagnostic according to the Diagnostic, PlotDiagnostic schema (#1712, #1896)\n\n## [v0.14.0]\n\nMain changes are:\n- AQUA is now open source\n- Documentation is now available on ReadTheDocs\n- Attributes added by AQUA are now "AQUA_" prefixed\n- A core diagnostic class has been introduced\n\nRemoved:\n- Support for python==3.9 has been dropped.\n- Generators option from the Reader has been removed.\n\nWorkflow modifications:\n- `aqua_analysis.py`: all the config files are used from the `AQUA_CONFIG` folder. This allows individual run modification kept in the `AQUA_CONFIG` folder for reproducibility.\n- `makes_contents.py`: can now take a config file as an argument to generate the `content.yaml` file.\n- `push_analysis.sh`: now has an option to rsync the figures to a specified location. Extra flags have been added (see Dashboard section in the documentation).\n\nAQUA core complete list:\n- Updated AQUA development container to micromamba 2.0.7 (#1834)\n- Updated base container to eccodes 2.40 (#1833)\n- Added Healpix zoom 7 grid for ICON R02B08 native oceanic grid (#1823)\n- Remove generators from Reader (#1791)\n- Fix tcc grib code and add some cmor codes in the convention file (#1800)\n- Add a regrid option to cli of relevant diagnostics (#1792)\n- Limit estimation of time for weight generation only to regular lon/lat grids (#1786)\n- LRA generation can operate spatial subsection (#1711)\n- Attributes added by AQUA are now "AQUA_" prefixed (#1790)\n- Remove zarr pin (#1794)\n- Dropping support for python==3.9 (#1778, #1797)\n- Reader intake-xarray sources can select a coder for time decoding (#1778)\n- Document use of AQUA on ECMWF HPC2020 (#1782)\n- Added history logging for lat-lon in area selection (#1479)\n- Cleaner workflow and pytest/coverage configuration (#1755, #1758)\n- catalog, model, exp, source info are now stored in the DataArray attributes (#1753)\n- Avoid infinite hanging during bridge access (#1733, #1738)\n- Enable dependabot to monitor dependencies every month (#1748)\n- `eccodes` bump to 2.40.0 (#1747)\n- Integrate codecov to monitor coverage and test analytics and remove old bot (#1736, #1737, #1755, #1819)\n- Reinitialize `GSVRetriever` instance only when needed (#1733)\n- Enable the option to read FDB data info from file, and refactor start/end hpc/bridge dates handling (#1732, #1743, #1762)\n- Fix `push_analysis.sh` options and `aqua_analysis.py` config paths (#1723, #1754)\n- Enable zip compression for LRA yearly files (#1726)\n- Enable publication of documentation on ReadTheDocs (#1699, #1716)\n- Adapt Catgen test to the new number of sources for ICON (#1708)\n- Added tests for the Hovmoller plot routine (#1532)\n- `push_s3` compatibility with `boto3>=1.36.0` (#1704)\n- Rsync option for push_analysis.sh (#1689)\n- Multiple updates to allow for AQUA open source, including Dockerfiles, actions, dependencies and containers (#1574)\n\nAQUA diagnostics complete list:\n- Ensemble: config file structure and tests (#1630)\n- Ocean3d: Tests for the Ocean3d diagnostic (#1780)\n- Diagnostic core: A common function to check and convert variable units is provided as `convert_data_units()` (#1806)\n- Ocean3d: Bug fix to regridding of observations in cli (#1811)\n- Diagnostic core: the `retrieve()` method uses internally a `_retrieve()` method that returns instead of updating attributes (#1763)\n- Diagnostic core: documentation about class and config file structure (#1790)\n- Diagnostic core: A common function to load the diagnostic config file is provided (#1750)\n- Global bias: add test (#1675)\n- Diagnostic core: Add additional command-line arguments for configuration and processing options (#1745)\n- Global bias: Handling plev and using scientific notation in contour plots (#1649)\n- Ecmean: Fix net surface radiative flux and wind stresses in ecmean (#1696)\n- Diagnostic core: A common parser and fuctions to open/close the dask cluster are provided (#1703)\n\n## [v0.13.1]\n\nMain changes are:\n1. Ocean3d major refactoring\n\nAQUA core complete list:\n- Fixer delete option accepts non-lists (#1687)\n- Ansi color 8-bit fix for logger (#1671)\n- Hotfix for unmatched string in catgen (#1672)\n- Test for aqua-analysis.py (#1664)\n- Fix in the catgen now correctly generating an automatic description if not provided (#1662)\n\nAQUA diagnostics complete list:\n- Diagnostic core: added a Diagnostic class to be inherited by all diagnostics (#1681)\n- Timeseries: hotfix of problems with the catalog usage in output saving (#1669)\n- Tropical Rainfall: Update of the precomputed histograms paths for lumi and MN5 (#1661)\n- Ocean3d: Trend is calculating using polyfit. Restructed the mixed layer depth function. (#1651)\n- Global bias: hotfix for regrid option (#1670)\n\n## [v0.13.0]\n\nMain changes are:\n1. Grids updated to work with operational O-25.1\n2. Compliance of the catalog generator to the O-25.1 data portfolio\n3. New \'Biases and Radiation\' diagnostics replace the old \'AtmGlobalMean and Radiation\'\n4. Push of figures to LUMI-O and improvements for aqua-web\n\nDeprecated:\n- `aqua-analysis.sh` script is deprecated and has been removed. Use `aqua-analysis.py` instead.\n- `cli_dummy.py` script is deprecated and will be removed in the next release. Use the `cli_checker.py` instead.\n \nAQUA core complete list:\n- More general checksum checker for grids and observations ( #1550)\n- Output dir including catalogue for aqua-analysis.py (#1640)\n- Grids for O-25.1 cycle are added in the grids folder (they are v3) (#1647)\n- `deltat` for fixer can now be specified in source metadata and not only in fixes (#1626)\n- LRA generator integrates ``--rebuild`` flag to regenerate areas and weights. The `--autosubmit` option is removed (#1623)\n- Hotfix for catgen tests (#1648)\n- Experiment and dashboard metadata are now created with the catalog generator (#1637)\n- Safety checks according to data frequency for HPC, bridge and request start/end dates in intake GSV (#1636, #1655)\n- Experiment metadata for aqua-web and dashboard from catalog entry (#1633)\n- Automatic identification of ocean grid in the catalog generator (#1621)\n- `OutputSaver` can deduce the catalog name from the model, exp (#1627)\n- Pin zarr<3.0.0 to avoid breaking changes (#1625)\n- Units utility are now functions and not methods of FixerMixin (#1558)\n- New `cli_checker.py` tool to check the existance of the required model in the catalog and rebuild the area files (#1619)\n- Update the catalog generator to align with changes in the data portfolio (#1593)\n- Adding ICON phase2 hpx6 and hpz9 grids (#1596)\n- Push figures to LUMI-O for dashboard (#1582, #1607)\n- Bridge_start_date and expver switching (#1597)\n- Include all available figure metadata in content.json for dashboard/aqua-web (#1573)\n- Upgrade LUMI module to 24.03 and to eccodes 2.39.0\n\nAQUA diagnostics complete list:\n- Old AtmoGlobalMean and Radiation diagnostics removed (#1622)\n- `--catalog` is accepted by all the diagnostics altough it is not used by all of them yet (#1619)\n- Timeseries: enabled region selection in the CLI (#1564)\n- Ocean3d: Bugfix of values for Ocean trend function (#1583)\n- Biases and Radiation: Refactoring of Bias and Radiation Diagnostics (#1243)\n- Biases and Radiation: Fix Seasonal Bias Output in global_biases for NetCDF Saving Compatibility and other fixes (#1585, #1604, #1628)\n- Biases and Radiation: Adding `save_netcdf` flag and function (#1510)\n- Biases and Radiation: Integrating Updated OutputSaver (#1487)\n\n## [v0.13-beta]\n\nMain changes are:\n1. All the diagnostics are now compatible with the new fixes and eccodes version.\n2. Full compatibility with HealPix grids and the new CDO version.\n3. Major improvements in the Ocean3D diagnostic.\n\nAQUA core complete list:\n- Safety checks and error messages on FDB folders (#1512)\n- Refreshed internal `to_list` function (#1512)\n- Reorganizing and extending CI/CD catalog with 5 years of hpz3 data from ERA5 (atm) and FESOM (oce) (#1552)\n- Version info in a separate module (#1546) \n- Corrected `tcc` units to % (#1551)\n- Fix pdf attributes (#1547)\n- Catgen fixes (#1536)\n- Introduced fixer for ClimateDT phase 2 (#1536)\n- `aqua_analysis.py` using a common central dask cluster (#1525)\n- Added the `cdo_options: "--force"` to the definitions of the oceanic HealPix grids (#1539)\n\nAQUA diagnostic complete list:\n- ECmean: Integrating the performance indices and global mean within the `aqua_diagnostics` module (#1556)\n- Teleconnections: The `teleconnections` diagnostic is now integrated in the `aqua_diagnostics` module (#1352)\n- Teleconnections: OutputSaver for the teleconnections diagnostic (#1567, #1570)\n- Ocean3d: Fix to improve memory usage and cli (#1490)\n- Seaice: Fix to read sithick as fallback instead of sivol (#1543)\n- Ocean3d: Minor fix to allow to read new variable names (#1540)\n- Timeseries: The `timeseries` diagnostic is now integrated in the `aqua_diagnostics` module (#1340)\n- Timeseries: Integrating Updated OutputSaver (#1492)\n\n## [v0.13-alpha]\n\nMain changes are:\n1. A refactor of the fixes, with a new common main convention table is available, based on eccodes.\n2. Diagnostics are updated to work with the new fixes and the new eccodes version. This is not yet complete and will be finalized in the next release.\n3. The FDB reader always rely on paramids, so that support for eccodes 2.39.0 and backward compatibility is ensured.\n\nAQUA core complete list:\n- push-analysis.sh maintenance (#1555)\n- Added the `cdo_options: "--force"` to the definitions of the HealPix grids (#1527)\n- Removing default fixes (#1519)\n- Support for eccodes=2.39.0 with full fixes refactoring (#1519)\n- Dashboard: Moved making of contents yaml to local hpc (#1470)\n- Support for new smmregrid==0.1.0 including simpler weights and area generation (#1395)\n- Removing cdo pin for more recent versions (#1395)\n- Change `bridge_end_date` convention (#1498)\n- `catgen` to support data bridge options (#1499)\n- Enhance OutputSaver with Improved File Handling, Logging, and NetCDF Write Modes (#1495)\n- Introduction a specific pipeline and tests for `catgen` utiliy (#1505)\n- Remove pin on xarray (#1507)\n- FDB reader internally always asks for paramids (#1491, #1508, #1529)\n- Introduction of a convention table for the fixer, in order to create a more general fixer (#1488, #1506)\n- Refactor of `cli_lra_parallel_slurm.py` to work with container via jinja (#1497) \n- Convert `aqua-analysis.sh` to Python with Subprocess and Multiprocessing Support (#1354, #1521)\n- New base container for aqua-container (#1441)\n- Autodetection of latest AQUA in `load-aqua-container.sh` script (#1437)\n- Update Metadata Handling for NetCDF, PDF, and PNG Outputs (#1430)\n- Add instructions to install AQUA on MN5 (#1468)\n- Introduce `grids-checker.py` tool to verify presence and checksum of the grid files (#1486)\n\nAQUA diagnostic complete list:\n- Tropical Cyclones: Adaptation to IFS-FESOM and tool to compute orography from data (#1393)\n- Seaice: Hotfix for sea ice plots (#1432)\n\n## [v0.12.2]\n\nMain changes are: \n1. Single container script to be used on Lumi, MN5 and Levante\n\nAQUA core complete list:\n- Introduce `timeshift` option for the fixer to roll forward/back the time axis (#1411)\n- Centralize and refactor in single script the tool to load AQUA container (#1413)\n- Add extra maintenance options to submit-aqua-web (#1415)\n- Update push-analysis.sh removing dependency on full AQUA and option not to convert to png (#1419)\n- Pin to xarray<2024.09 to prevent bug in polyfit requires temporary (#1420)\n- Remove spurious dimensions when running `fldmean()` (#1423)\n\nAQUA diagnostic complete list:\n- Refactor of plotThickness method in the sea ice diagnostic (#1427)\n\n\n## [v0.12.1]\n\nAQUA core complete list:\n- Allow multiple realizations in fdb-catalog-generator (#1335)\n- Fix the container loading script in order to avoid load of local libraries (#1399)\n- Fix using AQUA container for submit-aqua-web, do not wipe old figures by default (#1387)\n- New `timstat` module which opens complement `timmean()` with `timmax()`, `timmin()` and `timstd()` methods (#1391)\n- Fix installation to avoid mismatch between `hdf5` and `h5py` libraries (#1408)\n\n## [v0.12]\n\nMain changes are:\n1. AQUA installation now requires a mandatory machine name.\n2. The `aqua` source code has been moved to the `src` folder. The change is transparent to the user.\n3. A diagnostic module, called `aqua.diagnostics`, is under development. The module is not yet active, diagnostics are still available with the previous structure.\n\nAQUA core complete list:\n- Mixed updates to support data for NextGEMS cycle4 hackathon (#1375)\n- Preprocess functionality added to the `Reader` class (#1298)\n- The AQUAthon material has been moved under the `notebooks` folder (#1342)\n- `aqua` source code has been moved to the `src` folder (#1332)\n- A diagnostic module, called `aqua.diagnostics`, has been created under the `src` folder (#1332, #1341)\n- LRA generator tool support for multiple relizations (#1357, #1375)\n- LRA generator requires `catalog` as a mandatory argument (#1357)\n- AQUA console revisiting, adding `avail` method and `update` method (#1346)\n- AQUA install now requires mandatory machine name (#1346)\n- Fix to make keyword step optional in request (#1360)\n\n## [v0.11.3]\n\nAQUA core complete list:\n- LRA, both from CLI and worklow, is part of the AQUA console and can be run with `aqua lra $options` (#1294)\n- FDB catalog generator is part of the AQUA console and can be run with `aqua catgen $options` (#1294)\n- Coordinate unit overriding is now possible via the `tgt_units` argument (#1320)\n- Full support for python>=3.9 (#1325)\n- Pin of (python) eccodes<2.37.0 in pyproject due to recent changes in binary/python structure (#1325)\n\nAQUA diagnostic complete list:\n- Radiation: Bugfix in the CLI for the radiation diagnostic (#1319)\n\n## [v0.11.2]\n\nAQUA core complete list:\n- Renaming of FESOM grids to include original resolution name (#1312)\n- Bugfix of the fdb-catalog-generator tool that was not correctly assigning NEMO grids (#1309)\n- Bugfix of the GSV intake driver that was not handling correctly metadata jinja replacement (#1304) \n- Bugfix of _merge_fixes() method when the parent fix has no vars specified (#1310)\n- Safety check for the netcdf driver providing more informative error when files are not found (#1307, #1313)\n\nAQUA diagnostic complete list:\n- Tropical Rainfall: Fix Minor Issues in Tropical Precipitation CLI Metadata and Formatting (#1266)\n\n## [v0.11.1]\n\nAttention: If you are accessing FDB experiments, we suggest to not use versions older than this release.\n\nMain changes are:\n1. AQUA works with FDB written with ecCodes versions > 2.35 as well as lower.\n2. Timeseries and Seasonal cyle can now be evaluated also on a specific region \n\nAQUA core complete list:\n- ecCodes now pinned to >=2.36.0 and tool for fixing older definition files (#1302)\n\nAQUA diagnostic complete list:\n- Timeseries: a region can be selected for Timeseries and Seasonal Cycle with the `lon_limits` and `lat_limits` arguments (#1299)\n- Timeseries: the cli argument for extending the time range is now extend (previously expand) (#1299)\n- Timeseries: all the available diagnostics support the catalog argument (#1299)\n\n## [v0.11]\n\nAttention: this version is not compatible with catalog entries with ecCodes >= 2.35.0.\n\n1. LRA supports multi-catalog structure\n2. ecCodes temporarily restricted to < 2.34\n\nAQUA core complete list:\n- Refactor the fdb-catalog-generator tool to work with data-portfolio repository (#1275)\n- Introduce a function to convert NetCDF to Zarr and zarr catalog entry for LRA (#1068)\n- Suppress the warning of missing catalogs in the AQUA console `add` command (#1288)\n- Lumi installation is completely updated to LUMI/23.09 modules (#1290)\n- gsv_intake switches eccodes also for shortname definitions (#1279)\n- Increase compatibility between LRA generator and multi-catalog (#1278)\n- Allow for intake string replacement within LRA-generated catalogs (#1278)\n- Avoid warning for missing intake variable default when calling the `Reader()` (#1287)\n\nAQUA diagnostic complete list:\n- Teleconnections: catalog feature bugfix (#1276)\n\n## [v0.10.3]\n\nAttention: this version is not compatible with catalog entries with ecCodes < 2.35.0.\n\nMain changes are:\n1. support for ecCodes >= 2.35.0 (to be used with caution, not working with exps with eccodes < 2.35.0)\n2. fdb_path is deprecated in favour of fdb_home\n\nAQUA core complete list:\n- Restructure fixes folder and files (#1271)\n- Removed eccodes pin, better handling of tables in get_eccodes_attr (#1269)\n- Added test for diagnostics integration to AQUA installation process (#1244)\n- Bugfix for the monthly frequency data with monthly cumulated fluxes (#1255)\n- fdb_path becomes optional and deprecated in favour of fdb_home (#1262)\n- Branch support for tool to push analysis to explorer (#1273)\n\nAQUA diagnostic complete list:\n- ECmean documentation updates (#1264)\n\n## [v0.10.2]\n\nMain changes are:\n1. aqua-analysis script can be configured with an external yaml file\n2. AQUA installation process now includes diagnostics integration\n\nAQUA core complete list:\n- Rename OutputNamer to OutputSaver and add catalog name (#1259)\n- Hotfix for rare situation with 3D data but no vertical chunking defined (#1252)\n- External yaml file to configure aqua-analysis (#1246)\n- Adding diagnostics integration to AQUA installation process (#1229)\n\nAQUA diagnostic complete list:\n- Teleconnections: adding the catalog feature to the diagnostic (#1247)\n- ECmean upgrades for the CLI (#1241)\n- ECmean enables the computation of global mean diagostic (#1241)\n\n## [v0.10.1]\n\nAQUA core complete list:\n- Fixer for monthly frequency data with monthly cumulated fluxes (#1201)\n- Catalogs can be installed from the external repository (#1182)\n- Added grid for NEMO multiIO r100 (#1227)\n- Reorganized analysis output in catalog/model/exp structure (#1218)\n\n## [v0.10]\n\nMain changes are:\n1. The catalog is externalized and AQUA supports multiple catalogs. It is now mandatory to use the aqua console to add a new catalog to the AQUA installation.\n\nAQUA core complete list:\n- Catalog is externalized to a separate repository (#1200)\n- AQUA is now capable of accessing multiple catalogs at the same time (#1205)\n- MN5 container for AQUA (#1213)\n\n## [v0.9.2]\n\nMain changes are:\n1. The `aqua-config.yaml` file is replaced by a template to be installed. The aqua console is now mandatory to use aqua.\n2. `$AQUA` removed from the `Configdir()` autosearch, an installation with the aqua console is mandatory to use aqua.\n3. AQUA cli command to provide the installation path with `--path` option. This can substitute the `$AQUA` variable in scripts.\n4. The catalog file is now split into `machine.yaml` and `catalog.yaml` to support machine dependency of data path and intake variables as kwargs into each catalog.\n\nAQUA core complete list:\n- More detailed documentation for Levante and Lumi installation (#1210)\n- `aqua-config.yaml` replaced by a template to be installed on each machine (#1203)\n- `$AQUA` removed from the `Configdir()` autosearch (#1208)\n- AQUA cli command to provide the installation path with `--path` option (#1193)\n- Restructure of the `machine` and `catalog` instances to support a catalog based development (#1186)\n- AQUA installation via command line support a machine specification `aqua install lumi` (#1186)\n- Introduction of `machine.yaml` file to support machine dependency of data path and intake variables as kwargs into each catalog (#1186)\n- Removing all the AQUA catalogs from the repo, now using https://github.com/DestinE-Climate-DT/Climate-DT-catalog (#1200)\n\n## [v0.9.1]\n\nMain changes are:\n1. Update of fdb libraries to be compatible with the FDB data bridge\n\nAQUA core complete list:\n- OutputNamer Class: Comprehensive Naming Scheme and Metadata Support (#998)\n- Creation of png figures for AQUA explorer is local (#1189)\n\n## [v0.9]\n\nMain changes are:\n1. AQUA has an `aqua` CLI entry point, that allow for installation/uninstallation, catalog add/remova/update, fixes and grids handling\n2. Experiments placed half on HPC and half on DataBridge data can be accessed in continuous manner.\n\nAQUA core complete list:\n- AQUA entry point for installation and catalog maintanance and fixes/grids handling (#1131, #1134, #1146, #1168, #1169)\n- Automatic switching between HPC and databridge FDB (#1054, #1190)\n- CLI script for automatic multiple experiment analysis submission (#1160, #1175)\n\n## [v0.8.2]\n\nMain changes are: \n1. `aqua-grids.yaml` file split in multiple files into `grids` folder\n2. Container for Levante\n\nAQUA core complete list:\n- Removing any machine name depencency from slurm files (#1135)\n- Jinja replacement is added to the aqua-config.yaml (#1154)\n- grid definitions split in multiple files (#1152)\n- Add script to access the container on Levante HPC (#1151)\n- Add support for IFS TL63 and TL159 grids (#1150)\n- Swift links for tests and grids renewed (#1142)\n- Removing the docker folder (#1137)\n- Introducing a tool for benchmarking AQUA code (#1057)\n- Define AQUA NEMO healpix grids as a function of their ORCA source (#1113)\n\nAQUA diagnostics complete list:\n- Tropical Rainfall: Improve Paths in Live Demonstration Notebook  (#1157)\n- Atm global mean: produce seasonal bias plots by default (#1140)\n- Tropical Rainfall: Notebook for the Live Demonstration (#1112)\n- Teleconnections: MJO Hovmoller plot introduced as notebook (#247)\n- Tropical Rainfall: Reduce Redundancy in Conversion Functions (#1096)\n\n## [v0.8.1]\n\nMain changes are: \n1. Fixes following internal D340.7.3.3 and D340.7.1.4 review \n\nAQUA core complete list:\n- Tco399-eORCA025 control, historical and scenario runs added to Lumi catalog (#1070)\n- ESA-CCI-L4 dataset added for Lumi and Levante catalogs (#1090)\n- Various fixes to the documentation (#1106)\n- Fixer for dimensions is now available (#1050)\n\nAQUA diagnostics complete list:\n- Timeseries: units can be overridden in the configuration file (#1098)\n- Tropical Rainfall: Fixing the Bug in the CLI (#1100)\n\n## [v0.8]\n\nMain changes are:\n1. Support for Python 3.12\n2. Update in the catalog for Levante and introduction of Leonardo\n3. Multiple diagnostics improvement to fullfil D340.7.3.3 and D340.7.1.4\n\nAQUA core complete list:\n- LRA for ICON avg_sos and avg_tos (#1076)\n- LRA for IFS-NEMO, IFS-FESOM, ICON added to Levante catalog (#1072)\n- IFS-FESOM storyline +2K added to the Lumi catalog (#1059)\n- Allowing for jinja-based replacemente in load_yaml (#1045) \n- Support for Python 3.12 (#1052)\n- Extending pytests (#1053)\n- More efficient use of `_retrieve_plain` for acessing sample data (#1048)\n- Introducing the catalog structure for Leonardo HPC (#1049)\n- Introducing an rsync script between LUMI and levante for grids (#1044)\n- Introducing a basic jinja-based catalog entry generator (#853)\n- Adapt NextGEMS sources and fixes to the final DestinE governance (#1008, #1035)\n- Remove  NextGEMS cycle2 sources (#1008)\n- Avoid GSVSource multiple class instantiation in dask mode (#1051)\n\nAQUA diagnostics complete list:\n- Teleconnections: refactor of the documentation (#1061)\n- Tropical rainfall: Updating the Documentation and Notebooks (#1083)\n- Performance indices: minor improvements with the inclusion of mask and area files (#1076)\n- Timeseries: Seasonal Cycle and Gregory plots save netcdf files (#1079)\n- Tropical rainfall: minor modifications to the CLI and fixes to changes in the wrapper introduced in PR #1063 (#1074)\n- Tropical rainfall: adding daily variability and precipitation profiles to the cli (#1063)\n- Teleconnections: bootstrap evaluation of concordance with reference dataset (#1026)\n- SSH: Improvement of the CLI (#1024) \n- Tropical rainfall: adding metadata and comparison with era5 and imerg to the plots, re-binning of the histograms and buffering of the data (#1014)\n- Timeseries: refactor of the documentation (#1031)\n- Radiation: boxplot can accomodate custom variables (#933)\n- Seaice: convert to module, add Extent maps (#803)\n- Seaice: Implement seaice Volume timeseries and thickness maps (#1043)\n\n## [v0.7.3]\n\nMain changes are:\n1. IFS-FESOM NextGEMS4 and storylines simulations available in the catalog\n2. Vertical chunking for GSV intake access\n3. FDB monthly average data access is available\n4. kwargs parsing of reader arguments (e.g. allowing for zoom and ensemble support)\n\nAQUA core complete list:\n- Add kwargs parsing of reader arguments, passing them to intake to substitute parameters (#757)\n- Remove `zoom` and use kwargs instead (#757)\n- Enabling the memory monitoring and (optional) full performance monitoring in LRA (#1010)\n- Adding IFS_9-FESOM_5 NextGEMS4 simulation on levante (#1009)\n- Function to plot multiple maps is introduced as `plot_maps()` and documented (#866)\n- Adding the IFS-FESOM storylines simulation (#848)\n- `file_is_complete()` accounts also for the mindate attribute (#1007)\n- Introducing a `yearmonth` timestyle to access FDB data on monthly average (#1001)\n- Adding expected time calculation for weight generation (#701)\n- Vertical chunking for GSV intake access (#1003)\n\nAQUA diagnostics complete list:\n- Timeseries: Various bugfix and improvements for cli and formula (#1013, #1016, #1022)\n\n## [v0.7.2]\n\nMain changes are:\n1. `mtpr` is used for precipitation in all the catalog entries\n2. LRA CLI support for parallel SLURM submission and other improvements\n3. ICON production simulations available in the catalog\n4. `detrend()` method is available in the `Reader` class\n5. All the diagnostics have dask support in their CLI\n\nAQUA core complete list:\n- Fix LRA sources to allow incomplete times for different vars (#994)\n- Distributed dask option for diagnostic CLIs and wrapper (#981)\n- Added documentation for `plot_timeseries`, `plot_seasonalcycle` and `plot_single_map_diff` (#975)\n- Minimum date fixer feature / ICON net fluxes fix (#958)\n- Unified logging for all diagnostics (#931)\n- A `detrend()` method is added to the Reader class (#919)\n- LRA file handling improvements (#849, #972)\n- Updating fixer for ERA5 monthly and hourly data on Levante (#937)\n- GSV pin to 1.0.0 (#950)\n- Adding ICON production simulations (#925)\n- LRA CLI for parallel SLURM submission support a max number of concurrent jobs and avoid same job to run (#955, #990)\n- Renaming of EC-mean output figures in cli push tool for aqua-web (#930)\n- Renaming the `tprate` variable into `mtpr` in all fixes (#944)\n\nAQUA diagnostic complete list:\n- Tropical rainfall: enhancements of plotting and performance, files path correction (#997)\n- Timeseries: seasonal cycle runs as a separate cli in aqua-analysis for performance speed-up (#982)\n- Timeseries: seasonal cycle is added if reference data are not available in some timespan (#974)\n- Tropical rainfall: Removing unnecessary printing during the CLI, optimazing the CLi for low and high-resolution data (#963)\n- Timeseries: Grergory plot TOA limits are dynamically chosen (#959)\n- SSH: technical improvements including removal of hardcoded loglevel and timespan definition. (#677)\n- SSH: ready with new data governance and option to plot difference plots added. (#677)\n- Atmosferic Global Mean: added mean bias for the entire year in seasonal bias function (#947)\n- Tropical Cyclones: working with IFS-NEMO and ICON, includes retrieval of orography from file (#1071).\n\n## [v0.7.1]\n\nMain changes are:\n1. Complete update of the timeseries diagnostic\n2. LRA CLI for parallel SLURM submission\n3. SSP370 production scenario for IFS-NEMO available in the catalog\n\nAQUA core complete list:\n- Plot timeseries is now a framework function (#907)\n- Improve the automatic parsing of date range according to schema from fdb (#928)\n- LRA CLI for parallel SLURM submission (#909)\n- Added graphics function to plot data and difference between two datasets on the same map (#892)\n- Add IFS-NEMO ssp370 scenario (#906)\n\nAQUA diagnostics complete list:\n- Teleconnections: comparison with obs is done automatically in diagnostic CLI (#924)\n- Teleconnections: capability to find index file if already present (#926)\n- Timeseries: save flag introduced to save to enable/disable saving of the timeseries (#934)\n- Improve the automatic parsing of date range according to schema from fdb (#928)\n- Updated output filenames for atmglobalmean diagnostic (#921)\n- Added graphics function to plot data and difference between two datasets on the same map (#892)\n- Implemented `pyproject.toml` for global_time_series diagnostic (#920).\n- Implemented `pyproject.toml` for tropical_rainfall diagnostic (#850).\n- Updating CLi for tropical_rainfall diagnostic (#815)\n- LRA cli for parallel SLURM submission (#909)\n- Timeseries: seasonal cycle is available for the global timeseries (#912)\n- Timeseries: refactory of Gregory plot as a class, comparison with multiple models and observations (#910)\n- Add IFS-NEMO ssp370 scenario (#906)\n- Timeseries: complete refactory of the timeseries as a class, comparison with multiple models and observations (#907)\n- Plot timeseries is now a framework function (#907)\n\n## [v0.7]\n\nMain changes are:\n1. Multiple updates to the diagnostics, both scientific and graphical, to work with more recent GSV data\n2. `mtpr` is now used instead of `tprate` for precipitation\n2. Documentation has been reorganized and integrated\n\nComplete list:\n- New utility `add_pdf_metadata` to add metadata to a pdf file (#898)\n- Experiments `a0gg` and `a0jp` added to the IFS-NEMO catalog, and removal of `historical-1990-dev-lowres` (#889)\n- Updated notebooks to ensure consistency across different machines by using observational datasets, and included a demo of aqua components for Lumi (#868)\n- Scripts for pushing figures and docs to aqua-web (#880)\n- Fixed catalog for historical-1990-dev-lowres source (#888, #895)\n- data_models src files are now in the aqua/data_models folder, with minor modifications (#884)\n- Warning options based on the `loglevel` (#852)\n- Timeseries: formula bugfix and annual plot only for complete years (#876)\n- mtpr instead of tprate derived from tp (#828)\n- eccodes 2.34.0 does not accomodate for AQUA step approach, pin to <2.34.0 (#873)\n- Bugfix of the `aqua-analysis` wrapper, now can work teleconnections on atmospheric and oceanic variables \nand the default path is an absolute one (#859, #862)\n- Ocean3D: many fixes and adaptations to new data governance (#776)\n- Bugfix of the `aqua-analysis` wrapper, now can work teleconnections on atmospheric and oceanic variables (#859)\n- Radiation: adaptation to new data governance and many improvements (#727)\n- Seaice: Sea ice extent has now seasonal cycle (#797)\n- Fixing the paths in `cli/lumi-install/lumi_install.sh` (#856).\n- Refactor of the documentation (#842, #871)\n- The drop warning in `aqua/gsv/intake_gsv.py` (#844)\n- Tropical cyclones diagnostic: working with new data governance (includes possibility to retrieve orography from file (#816)\n\n## [v0.6.3]\n\nComplete list:\n- Setting last date for NaN fix for IFS-NEMO/IFS-FESOM to 1999-10-01 and cleaner merge of parent fixes (#819)\n- Hotfix to set `intake==0.7.0` as default (#841)\n- Timeseries: can add annual std and now default uncertainty is 2 std (#830)\n- `retrieve_plain()` method now set off startdate and enddate (#829)\n- Complete restructure of fixer to make use of `fixer_name`: set a default for each model and a `False` to disable it (#746)\n- Added `center_time` option in the `timmean()` method to save the time coordinate in the middle of the time interval and create a Timmean module and related TimmeanMixin class (#811)\n- Fixer to rename coordinates available (#822)\n- Fixing new pandas timedelta definition: replacing H with h in all FDB catalog (#786)\n- Change environment name from `aqua_common` to `aqua`(#805)\n- Adding a run test label to trigger CI (#826)\n- Tropical_rainfall: improve organization and maintainability, introducing nested classes (#814)\n- Revisiting CERES fixes (#833)\n- Timeseries: add bands for observation in Gregory plots (#837)\n\n## [v0.6.2]\n\nComplete list:\n- Global time series plot annual and monthly timeseries together, improved Gregory plot (#809)\n- Teleconnection can now take a time range as input and ylim in the index plot function (#799)\n- LRA to use `auto` final time and `exclude_incomplete` (#791)\n- Hotfix for v0.12.0 of the GSV_interface related to valid_time (#788)\n- Global time series adapted to new data governance (#785)\n- AtmoGlobalMean diagnostic improvements and adaptation to new data governance (#745 #789 #807 #812)\n- Sea-ice diagnostic adapted to new data governance (#790)\n- Implement a fix setting to NaN the data of the first step in each month (for IFS historical-1990) (#776)\n\n## [v0.6.1]\n\nComplete list:\n- Teleconnection improvement to accept different variable names for ENSO (avg_tos instead of sst) (#778)\n- ERA5 fixes compatible with new data governance (#772)\n- Update the LRA generator (removing aggregation and improving) filecheck and fix entries for historical-1990-dev-lowres (#772)\n- Updates of ECmean to work with production experiments (#773, #780)\n- Automatic data start and end dates for FDB sources (#762)\n\n## [v0.6]\n\nMain changes are:\n1. Inclusion in the catalog of the historical-1990 production simulations from IFS-NEMO and IFS-FESOM.\n2. New fixes that targets the DestinE updated Data Governance\n\nComplete list:\n- IFS-FESOM historical-1990-dev-lowres with new data governance added to the catalog (#770)\n- AtmoGlobalMean diagnostic improvements (#722)\n- Teleconnections diagnostic improvements (#722)\n- Read only one level for retrieving 3D array metadata, select single level for retrieve (#713)\n- IFS-FESOM historical-1990-dev-lowres with new data governance added to the catalog\n- Fix mismatch between var argument and variables specified in catalog for FDB (#761)\n- Compact catalogs using yaml override syntax (#752)\n- Fix loading source grid file before smmregrid weight generation (#756)\n\n## [v0.5.2-beta]\n\nComplete list:\n-  A new fdb container is used to generate the correct AQUA container\n\n## [v0.5.2-alpha]\n\nMain changes are:\n1. Coupled models IFS-NEMO and IFS-FESOM are now supported\n2. Accessor to use functions and reader methods as if they were methods of xarray objects, see [notebook](https://github.com/DestinE-Climate-DT/AQUA/blob/main/notebooks/reader/accessor.ipynb)\n3. Preliminary provenance information is now available in the history attribute of the output files\n4. AQUA analysis wrapper is parallelized\n5. A levelist can be provided in FDB sources, this will greatly speed up the data retrieve\n\nComplete list:\n- Fix reading only one sample variable and avoid _bnds variables (#743)\n- Allow correct masked regridding after level selection. Add level selection also for not-FDB sources (#741)\n- Read only one level for retrieving 3D array metadata, select specific levels for FDB retrieve (#713)\n- Defining catalog entry for coupled models IFS-NEMO and IFS-FESOM (#720)\n- Change fixer_name to fixer_name (#703)\n- Reorganization of logging calls (#700)\n- Accessor to use functions and reader methods as if they were methods of xarray objects (#716)\n- Suggestions are printed if a model/exp/source is not found while inspecting the catalog (#721)\n- Improvements in the single map plot function (#717)\n- Minor metadata fixes (logger newline and keep "GRIB_" in attrs) (#715)\n- LRA fix now correctly aggregating monthly data to yearly when a full year is available (#696)\n- History update and refinement creating preliminary provenance information (plus AQUA emoji!) (#676)\n- OPA lra compatible with no regrid.yaml (#692)\n- Introducing fixer definitions not model/exp/source dependents to be specified at the metadata level (#681)\n- AQUA analysis wrapper is parallelized and output folder is restructured (#684, #725)\n\n## [v0.5.1]\n\nMain changes are:\n1. A new `Reader` method `info()` is available to print the catalog information\n2. Grids are now stored online and a tool to deploy them on the `cli` folder is available\n\nComplete list:\n- Fix attributes of DataArrays read from FDB (#686)\n- Reader.info() method to print the catalog information (#683)\n- Simpler reader init() by reorganizing the calls to areas and regrid weights configuration and loading (#682)\n- Optional autosearch for vert_coord (#682)\n- plot_single_map adapted to different coordinate names and bugfixes (#680)\n- Sea ice volume datasets for the Northern Hemisphere (PIOMAS) and the Southern Hemisphere (GIOMAS) (#598)\n- Possibility of defining the regrid method from the grid definition (#678)\n- Grids stored online and tool to deploy them on cli folder (#675)\n- Global time series diagnostic improvements (#637)\n- Teleconnections diagnostic improvements (#672)\n\n## [v0.5]\n\nMain changes are:\n1. Refactor of the Reader() interface with less options at the init() level\n2. Grids are now defined with the source metadata and not in a machine-dependent file\n3. CLI wrapper is available to run all diagnostics in a single call\n4. Refactoring of the streaming emulator with equal treatment for FDB or file sources\n\nComplete list:\n- Controlling the loglevel of the GSV interface (#665)\n- Fix wrong fdb source (#657)\n- Adding sample files and tests for NEMO 2D and 3D grids (#652)\n- tprate not derived from tp for GSV sources (#653)\n- Simplify reader init and retrieve providing less argument in initialization (#620)\n- var=\'paramid\' can be used to select variables in the retrieve method (#648)\n- configdir is not searched based on util file position in the repo (#636)\n- Cleaner mask treatment (Revision of mask structure in the reader #617)\n- Fldmean fix if only one dimension is present for area selection (#640)\n- Adding higher frequency ERA5 data on Levante and Lumi (#628)\n- regrid.yaml files are removed, grid infos are now in the catalog metadata (#520, #622, #643)\n- Load all available variables in FDB xarray/dask access (#619)\n- Lint standard and enforced in CI (#616)\n- Reader init split with methods (#523)\n- Single map plot utility to be used by all diagnostics (#594)\n- Script for automatic generation of Fdb catalog entries (IFS only) (#572)\n- Fix loading of singularity mounting /projappl (#612)\n- CLI wrapper parser (#599)\n- Refactoring of streaming emulator (#593)\n- Radiation CLI and diagnostic refinement (#537)\n- Ocean3D CLI and diagnostic refinement (#578)\n- AtmGlobalMean CLI and diagnostic refinement (#587)\n- Tropical cyclones CLI refinements and TC module (#568, #645)\n- Removing OPA, OPAgenerator and related tests from the AQUA (Remove OPA from AQUA #586)\n- Renaming the experiments according to the DE340 AQUA syntax (Including dev-control-1990 in the source and rename the experiment according to DE340 scheme #556, #614, #618)\n- Teleconnections diagnostic improvements (#571, #574, #576, #581, #592, #623)\n\n## [v0.4]\n\nMain changes are:\n1. Update to all the diagnostics CLI\n2. Refactor of the regridder so that `regrid.yaml`` is grid-based and not experiment-based\n3. Xarray access to FDB sources\n4. Refactor of the fixer so that merge/replace/default options are available\n5. Remove of the `aqua` environment in favour of the `aqua_common` one. \n\nComplete list:\n- Introduced color scheme for aqua logging (#567)\n- CLI for sea diagnostic (#549)\n- Add CLI for SSH diagnostic and some bug fixes (#540)\n- Fix SSH diagnostic to be compatible with lates AQUA version (#538) \n- Helper function to identify vertical coordinates in a dataset (#552)\n- Orography for tempest extremes TCs detection and update TCs CLI (Orography threshold included and CLI update #404)\n- Improvement of performance indices CLI (Update of ECmean CLI #528)\n- Fix to allow reading a list of multiple variables from FDB (#545)\n- Further improvement of function to inspect the catalog (#533)\n- Custom exceptions for AQUA (#518)\n- Speed up of the `retrieve_plain` method (#524)\n- Update documention for adding new data and setting up the container (Increase documentation coverage #519)\n- CLI wrapper for the state-of-the-art diagnostics analysis (#517, #527, #525, #530, #534, #536, #539, #548, #549, #559)\n- Refactor the regrid.yaml as grid-based instead of experiment-based (#291)\n- aqua_common environment simplified and updated (#498)\n- Update available variables in FDB catalogs on lumi (#514)\n- Solve reversed latitudes bug for fixed data (#510)\n- Switch to legacy eccodes tables based on intake source metadata (#493)\n- Add GPM IMERG precipitation data to the catalog on levante (#505)\n- Fix ocean3d diagnostic colorbars not being symmetric when missing values are present (#504) \n- FDB NEMO test access to data (#488)\n- Xarray dask access to FDB (#476)\n- Issue a warning when multiple gribcodes are associated to the same shortname (Cases for multiple eccodes grib codes #483)\n- Allowing fixer to overwrite or merge default configuration (Increasing flexibiity of the fixer allowing for merge, replace and default options #480)\n- Add new tests (Increase testing #250)\n- Global time series diagnostic setup for multiple variables CLI (#474)\n- Option to avoid incomplete chunk when averagin with timmean (Introduce check for chunk completeness in timmean() #466)\n- Simplification of Fixer() workflow, more methods and less redundancy (Functionize fixer #478)\n- Remove the `aqua` environment file, only `aqua_common` is left (#482)\n\n## [v0.3]\n\nMain changes are:\n1. Fixer moved at `Reader()` level\n2. Area selection available in `fldmean()` method\n3. FDB/GSV access for IFS-NEMO development simulations\n4. Configuration file `config-aqua.yaml` replaces `config.yaml`\n\nComplete list:\n- Templates in configuration yaml files (#469)\n- Bug fixes for FDB access options (#463, #462)\n- Add observational catalogs on Lumi (Update Lumi catalog #454)\n- Automatic finding of cdo (#456)\n- Area is fixed if data are fixed (Fixer applied to grid areas #442)\n- Tests missing failure fix (Fix #436 CI workflow passes even if some tests fail #452)\n- FDB/GSV access to IFS control and historical simulations (#434, #458)\n- Climatology support restored in the Reader (Fix for climatology #445)\n- Improvement function to inspect the catalog (Inspect_catalog improvement #446)\n- Minor improvements of the gribber (Fix gribber fdb #427)\n- Allow the LRA generator to work with generators and so with FDB (LRA from fdb on mafalda #430)\n- Fixes only on selected variables (Fixer updates #428)\n- Complete revision of the FDB/GSV access, allowing to access also recent experiments using variable step (#343)\n- Teleconnections diagnostic adapted to new code improvements (Teleconnections Dev branch update #424, #465)\n- Add support for area selection with fldmean (Fldmean box selection #409)\n- Environment simplified, dependencies are now mostly on the pyproject file (A simpler environment.yml #286)\n- Intake esm functionality added back (Fix intake-esm #287)\n- Intake esm tests (Test also intake-esm #335)\n- Yaml dependencies removed (Logger and yaml issues in util.py #334)\n- Log history working for iterators as well (Logger and yaml issues in util.py #334)\n- Util refactor (Utility refactor #405)\n- Fixer at reader level (Fixes at Reader level #244)\n- Uniform timmean (Uniform time after timmean and add option for time_bnds #419)\n- FDB tests added (Add FDB 5.11, a local FDB with some test data #280, #432)\n- Refactor of unit conversion and non-metpy cases (Flexible unit fix from YAML file #416)\n- Refactor of the config file definition (Refactor of the configuration search #417)\n\n## [v0.2.1]\n\n- Add development control-1950 and historical-1990 experiments to the LRA (LRA for control-1950 and historical-1990 on Levante from v0.2 #455)\n\n## [v0.2]\n\n- Improve the LRA generator and worklow CLI (Streaming for the LRA #289)\n- AQUA new common environment installation tool for LUMI added (#413)\n- Added a bash script "load_aqua_lumi.sh" to load aqua environment in LUMI with containers (Adding an AQUA singularity container for LUMI #418)\n\n## [v0.2-beta]\n\nThis is the `AQUA` version part of the Deliverable D340.7.1.2. \n\n- SSH diagnostic improvements (Linting SSH diagnostics #377, SSH diag: PDF file name changed #388)\n- Timmean fix to uniform time axis (Fix for timmean() to uniform output time axis #381)\n- New tests trigger routine (Tests trigger with label #385)\n- Fix for tco1279 and FESOM (fix for masked tco1279 #390, psu fix for salinity #383)\n- ECmean improvements (various improvement for ecmean #392)\n- Seaice diagnostic improvements (Deliverable340.7.1.2 fix seaice #389, Linting Seaice diagnostics #376)\n- Teleconnections diagnostic graphics module enhanced and various improvements (Teleconnections corrections for D340.7.1.2 #379, Fix import in teleconnections notebooks #395, Teleconnections fix docs #408)\n- Tropical cyclones linting of the diagnostic (Linting tropical cyclones diagnostics #380, Improved plotting functions for tropical cyclones #391)\n- Ocean diagnostics restructured in a single folder, sharing common functions and other improvements (Linting+Fixes Ocean diagnostics #374, Adding units for MLD plot in ocean3d package #406)\n- Documentation fixes (Documentation fixes after review #403)\n- Atmglobalmean and radiation diagnostic improvements (Atmglobalmean fix #371)\n- MSWEP fixer bugfix (Change MSWEP datamodel #397, fixing of mswep #401)\n\n## [v0.2-alpha]\n\nThis is the `AQUA` version that will be part of the Deliverable D340.7.1.2, sent to internal review. This is mostly done by the inclusion of twelve diagnostics within the AQUA framework\n\n- Added teleconnections diagnostic (#308, #309, #318, #333, #352)\n- Added tropical cyclones diagnostic (#310, #345)\n- Added performance indices diagnostic based on ECmean tool (#57, #327) \n- Added sea ice diagnostic (#353, #368)\n- Added global timeseries diagnostic (#358, #359)\n- Added radiation analysis diagnostic (#301, #360)\n- Added global mean bias diagnostic (#285, #371)\n- Added SSH variability diagnostic (#367, #369)\n- Added tropical rainfall diagnostic (#314)\n- Added Ocean circulation diagnostic (#295)\n- Added global ocean diagnosc (#164)\n- Added global mean timeseries (#268)\n- Multiple fixes in the Reader (#316, #324, #334)\n- Avoid time duplicated in the Reader (#357)\n- Enabling autodoc for diagnostics (#330)\n- Data access improvement on Levante, including new datasets (#332, #355, #321)\n- Added a common environment file (#363)\n- Support for Lumi installation (#315)\n- Added the `changelog` file\n\n### Changed\n\n- Dummy diagnostic is now in the `dummy` folder (previously was `dummy-diagnostic`)\n- Tests and code is now working with python>=3.9 (previously python 3.11 was excluded)\n\n## [v0.1-beta]\n\nThis is the `AQUA` version that will be part of the Deliverable D340.7.1.1.\nThis is mostly built on the `AQUA` `Reader` class which support for climate model data interpolation, spatial and temporal aggregation and conversion for a common GRIB-like data format.\n\n\n- Low resolution archive documentation\n- Fixed a bug in the `Gribber` class that was not reading the correct yaml catalog file\n\n## v0.1-alpha\n\nThis is the AQUA pre-release to be sent to internal reviewers. \nDocumentations is completed and notebooks are working.\n\n[unreleased]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.17.0...HEAD\n[v0.17.0]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.16.0...v0.17.0\n[v0.16.0]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.15.0...v0.16.0\n[v0.15.0]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.14.0...v0.15.0\n[v0.14.0]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.13.1...v0.14.0\n[v0.13.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.13.0...v0.13.1\n[v0.13.0]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.13-beta...v0.13.0\n[v0.13-beta]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.13-alpha...v0.13-beta\n[v0.13-alpha]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.12.2...v0.13-alpha\n[v0.12.2]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.12.1...v0.12.2\n[v0.12.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.12...v0.12.1\n[v0.12]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.11.3...v0.12\n[v0.11.3]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.11.2...v0.11.3\n[v0.11.2]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.11.1...v0.11.2\n[v0.11.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.11...v0.11.1\n[v0.11]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.10.3...v0.11\n[v0.10.3]:https://github.com/DestinE-Climate-DT/AQUA/compare/v0.10.2...v0.10.3\n[v0.10.2]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.10.1...v0.10.2\n[v0.10.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.10...v0.10.1\n[v0.10]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.9.2...v0.10\n[v0.9.2]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.9.1...v0.9.2\n[v0.9.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.9...v0.9.1\n[v0.9]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.8.2...v0.9\n[v0.8.2]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.8.1...v0.8.2\n[v0.8.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.8...v0.8.1\n[v0.8]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.7.3...v0.8\n[v0.7.3]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.7.2...v0.7.3\n[v0.7.2]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.7.1...v0.7.2\n[v0.7.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.7...v0.7.1\n[v0.7]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.6.3...v0.7\n[v0.6.3]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.6.2...v0.6.3\n[v0.6.2]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.6.1...v0.6.2\n[v0.6.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.6...v0.6.1\n[v0.6]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.5.2-beta...v0.6\n[v0.5.2-beta]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.5.2-alpha...v0.5.2-beta\n[v0.5.2-alpha]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.5.1...v0.5.2-alpha\n[v0.5.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.5...v0.5.1\n[v0.5]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.4...v0.5\n[v0.4]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.3...v0.4\n[v0.3]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.2.1...v0.3\n[v0.2.1]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.2...v0.2.1\n[v0.2]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.2-beta...v0.2\n[v0.2-beta]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.2-alpha...v0.2-beta\n[v0.2-alpha]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.1-beta...v0.2-alpha\n[v0.1-beta]: https://github.com/DestinE-Climate-DT/AQUA/compare/v0.1-alpha...v0.1-beta\n',
            'src/aqua/reader/reader.py': '"""The main AQUA Reader class"""\n\nfrom contextlib import contextmanager\nimport intake_esm\nimport intake_xarray\nimport xarray as xr\nfrom metpy.units import units\n\nfrom smmregrid import GridInspector\n\nfrom aqua.util import load_multi_yaml, files_exist, to_list\nfrom aqua.util import ConfigPath, find_vert_coord\nfrom aqua.logger import log_configure, log_history\nfrom aqua.exceptions import NoDataError, NoRegridError\nfrom aqua.version import __version__ as aqua_version\nfrom aqua.regridder import Regridder\nfrom aqua.fldstat import FldStat\nfrom aqua.timstat import TimStat\nfrom aqua.fixer import Fixer\nfrom aqua.data_model import counter_reverse_coordinate\nfrom aqua.histogram import histogram\nimport aqua.gsv\n\nfrom .streaming import Streaming\nfrom .trender import Trender\n\nfrom .reader_utils import set_attrs\n\n# set default options for xarray\nxr.set_options(keep_attrs=True)\n\nclass Reader():\n    """General reader for climate data."""\n\n    instance = None  # Used to store the latest instance of the class\n\n    def __init__(self, model=None, exp=None, source=None, catalog=None,\n                 fix=True,\n                 regrid=None, regrid_method=None,\n                 areas=True, \n                 streaming=False,\n                 startdate=None, enddate=None,\n                 rebuild=False, loglevel=None, nproc=4,\n                 aggregation=None, chunks=None,\n                 preproc=None, convention=\'eccodes\',\n                 engine=\'fdb\',\n                 **kwargs):\n        """\n        Initializes the Reader class, which uses the catalog\n        `config/config.yaml` to identify the required data.\n\n        Args:\n            model (str): Model ID. Mandatory\n            exp (str): Experiment ID. Mandatory.\n            source (str): Source ID. Mandatory\n            catalog (str, optional): Catalog where to search for the triplet.  Default to None will allow for autosearch in\n                                     the installed catalogs.\n            regrid (str, optional): Perform regridding to grid `regrid`, as defined in `config/regrid.yaml`. Defaults to None.\n            regrid_method (str, optional): CDO Regridding regridding method. Read from grid configuration.\n                                           If not specified anywhere, using "ycon".\n            fix (bool, optional): Activate data fixing\n            areas (bool, optional): Compute pixel areas if needed. Defaults to True.\n            streaming (bool, optional): If to retrieve data in a streaming mode. Defaults to False.\n            startdate (str, optional): The starting date for reading/streaming the data (e.g. \'2020-02-25\'). Defaults to None.\n            enddate (str, optional): The final date for reading/streaming the data (e.g. \'2020-03-25\'). Defaults to None.\n            rebuild (bool, optional): Force rebuilding of area and weight files. Defaults to False.\n            loglevel (str, optional): Level of logging according to logging module.\n                                      Defaults to log_level_default of loglevel().\n            nproc (int, optional): Number of processes to use for weights generation. Defaults to 4.\n            aggregation (str, optional): the streaming frequency in pandas style (1M, 7D etc. or \'monthly\', \'daily\' etc.)\n                                         Defaults to None (using default from catalog, recommended).\n            chunks (str or dict, optional): chunking to be used for GSV access.\n                                            Defaults to None (using default from catalog, recommended).\n                                            If it is a string time chunking is assumed.\n                                            If it is a dictionary the keys \'time\' and \'vertical\' are looked for.\n                                            Time chunking can be one of S (step), 10M, 15M, 30M, h, 1h, 3h, 6h, D, 5D, W, M, Y.\n                                            Vertical chunking is expressed as the number of vertical levels to be used.\n            preproc (function, optional): a function to be applied to the dataset when retrieved. Defaults to None.\n            convention (str, optional): convention to be used for reading data. Defaults to \'eccodes\'.\n                                        (Only one supported so far)\n            engine (str, optional): Engine to be used for GSV retrieval: \'polytope\' or \'fdb\'. Defaults to \'fdb\'.\n\n        Keyword Args: \n            zoom (int, optional): HEALPix grid zoom level (e.g. zoom=10 is h1024). Allows for multiple gridname definitions.\n            realization (int, optional): The ensemble realization number, included in the output filename.\n            **kwargs: Additional arbitrary keyword arguments to be passed as additional parameters to the intake catalog entry.\n\n        Returns:\n            Reader: A `Reader` class object.\n        """\n\n        Reader.instance = self  # record the latest instance of the class (used for accessor)\n\n        # define the internal logger\n        self.loglevel = loglevel\n        self.logger = log_configure(log_level=self.loglevel, log_name=\'Reader\')\n\n        self.exp = exp\n        self.model = model\n        self.source = source\n        # these infos are used by the regridder to correct define areas/weights name\n        reader_kwargs = {\'model\': model, \'exp\': exp, \'source\': source}\n        self.regrid_method = regrid_method\n        self.nproc = nproc\n        self.vert_coord = None\n        self.time_correction = False  # extra flag for correction data with cumulation time on monthly timescale\n        self.aggregation = aggregation\n        self.chunks = chunks\n\n        # Preprocessing function\n        self.preproc = preproc\n\n        # init the areas and dimensions\n        self.grid_area = None\n        self.src_grid_area = None\n        self.tgt_grid_area = None\n        self.src_space_coord = None\n        self.tgt_space_coord = None\n        self.vert_coord = None\n\n        if streaming:\n            self.streamer = Streaming(startdate=startdate,\n                                      enddate=enddate,\n                                      aggregation=aggregation,\n                                      loglevel=self.loglevel)\n            # Export streaming methods TO DO: probably useless\n            self.reset_stream = self.streamer.reset\n            self.stream = self.streamer.stream\n        self.streaming = streaming\n\n        self.startdate = startdate\n        self.enddate = enddate\n\n        self.sample_data = None  # used to avoid multiple calls of retrieve_plain\n\n        # define configuration file and paths\n        configurer = ConfigPath(catalog=catalog, loglevel=loglevel)\n        self.configdir = configurer.configdir\n        self.machine = configurer.get_machine()\n        self.config_file = configurer.config_file\n        self.cat, self.catalog_file, self.machine_file = configurer.deliver_intake_catalog(\n            catalog=catalog, model=model, exp=exp, source=source)\n        self.fixer_folder, self.grids_folder = configurer.get_reader_filenames()\n\n        # deduce catalog name\n        self.catalog = self.cat.name\n\n        # machine dependent catalog path\n        machine_paths, intake_vars = configurer.get_machine_info()\n\n        # load the catalog\n        aqua.gsv.GSVSource.first_run = True  # Hack needed to avoid double checking of paths (which would not work if on another machine using polytope)\n        self.expcat = self.cat(**intake_vars)[self.model][self.exp]  # the top-level experiment entry\n        # We open before without kwargs to filter kwargs which are not in the parameters allowed by the intake catalog entry\n        self.esmcat = self.expcat[self.source]()\n        self.kwargs = self._filter_kwargs(intake_vars, kwargs, engine=engine)\n        self.esmcat = self.expcat[self.source](**self.kwargs)\n\n        # Manual safety check for netcdf sources (see #943), we output a more meaningful error message\n        if isinstance(self.esmcat, intake_xarray.netcdf.NetCDFSource):\n            if not files_exist(self.esmcat.urlpath):\n                raise NoDataError(f"No NetCDF files available for {self.model} {self.exp} {self.source}, please check the urlpath: {self.esmcat.urlpath}")  # noqa E501\n\n        # extend the unit registry\n        units_extra_definition()\n        # Get fixes dictionary and find them\n        self.fix = fix  # fix activation flag\n        self.fixer_name = self.esmcat.metadata.get(\'fixer_name\', None)\n        self.convention = convention\n        if self.convention is not None and self.convention != \'eccodes\':\n            raise ValueError(f"Convention {self.convention} not supported, only \'eccodes\' is supported so far.")\n\n        # case to disable automatic fix\n        if self.fixer_name is False:\n            self.logger.warning(\'A False flag is specified in fixer_name metadata, disabling fix!\')\n            self.fix = False\n\n        if self.fix:\n            self.fixes_dictionary = load_multi_yaml(self.fixer_folder, loglevel=self.loglevel)\n            self.fixer = Fixer(fixer_name=self.fixer_name,\n                               convention=self.convention,\n                               fixes_dictionary=self.fixes_dictionary,\n                               metadata=self.esmcat.metadata,\n                               loglevel=self.loglevel)\n            \n    \n        # define grid names\n        self.src_grid_name = self.esmcat.metadata.get(\'source_grid_name\')\n        self.tgt_grid_name = regrid\n\n        # init the regridder and the areas\n        self._configure_regridder(machine_paths, regrid=regrid, areas=areas,\n                                  rebuild=rebuild, reader_kwargs=reader_kwargs)\n        \n        # init the fldstat modules. if areas are not available, will issue a warning\n        cell_area = self.src_grid_area.cell_area if areas else None\n        self.src_fldstat = FldStat(\n            cell_area, grid_name=self.src_grid_name,\n            horizontal_dims=self.src_space_coord, loglevel=self.loglevel\n            )\n        self.tgt_fldstat = None\n        if regrid:\n            self.tgt_fldstat = FldStat(\n                self.tgt_grid_area.cell_area, grid_name=self.tgt_grid_name,\n                horizontal_dims=self.tgt_space_coord, loglevel=self.loglevel\n                )\n            \n        self.trender = Trender(loglevel=self.loglevel)\n\n    def _configure_regridder(self, machine_paths, regrid=False, areas=False,\n                             rebuild=False, reader_kwargs=None):\n        """\n        Configure the regridder and generate areas and weights.\n\n        Arguments:\n            machine_paths (dict): The machine specific paths. Used to configure regridder file paths\n            regrid (bool): If regrid is required. Defaults to False.\n            areas (bool): If areas are required. Defaults to False.\n            rebuild (bool): If weights and areas should be rebuilt. Defaults to False.\n            reader_kwargs (dict): The reader kwargs.\n        """\n\n        # load and check the regrid\n        if regrid or areas:\n\n            # create the configuration dictionary\n            cfg_regrid = load_multi_yaml(folder_path=self.grids_folder,\n                                         definitions=machine_paths[\'paths\'],\n                                         loglevel=self.loglevel)\n            cfg_regrid = {**machine_paths, **cfg_regrid}\n\n            if self.src_grid_name is None:\n                self.logger.warning(\'Grid metadata is not defined. Trying to access the real data\')\n                data = self._retrieve_plain()\n                self.regridder = Regridder(cfg_regrid, data=data, loglevel=self.loglevel)\n            else:\n                self.logger.info(\'Grid metadata is %s\', self.src_grid_name)\n                self.regridder = Regridder(cfg_regrid, src_grid_name=self.src_grid_name, \n                                           loglevel=self.loglevel)\n\n                if self.regridder.error:\n                    self.logger.warning(\'Issues in the Regridder() init: trying with data\')\n                    data = self._retrieve_plain()\n                    self.regridder = Regridder(cfg_regrid, src_grid_name=self.src_grid_name, \n                                               data=data, loglevel=self.loglevel)\n\n            # export src space coord and vertical coord\n            self.src_space_coord = self.regridder.src_horizontal_dims\n            self.vert_coord = self.regridder.src_vertical_dim\n\n            # TODO: it is likely there are other cases where we need to disable regrid.\n            if not self.regridder.cdo:\n                areas = False\n                regrid = False\n\n\n        # generate source areas\n        if areas:\n            # generate source areas and expose them in the reader\n            self.src_grid_area = self.regridder.areas(rebuild=rebuild, reader_kwargs=reader_kwargs)\n            if self.fix:\n                # TODO: this should include the latitudes flipping fix.\n                # TODO: No check is done on the areas coords vs data coords\n                self.src_grid_area = self.fixer.datamodel.fix_area(self.src_grid_area)\n\n        # configure regridder and generate weights\n        if regrid:\n            # generate weights and init the SMMregridder\n            self.regridder.weights(\n                rebuild=rebuild,\n                tgt_grid_name=self.tgt_grid_name,\n                regrid_method=self.regrid_method,\n                reader_kwargs=reader_kwargs)\n\n        # generate destination areas, expost them and the associated space coordinates\n        if areas and regrid:\n            self.tgt_grid_area = self.regridder.areas(tgt_grid_name=self.tgt_grid_name, rebuild=rebuild)\n            if self.fix:\n                # TODO: this should include the latitudes flipping fix\n                self.tgt_grid_area = self.fixer.datamodel.fix_area(self.tgt_grid_area)\n            self.tgt_space_coord = self.regridder.tgt_horizontal_dims\n\n        # activste time statistics\n        self.timemodule = TimStat(loglevel=self.loglevel)\n\n    def retrieve(self, var=None, level=None,\n                 startdate=None, enddate=None,\n                 history=True, sample=False):\n        """\n        Perform a data retrieve.\n\n        Arguments:\n            var (str, list): the variable(s) to retrieve. Defaults to None. If None, all variables are retrieved.\n            level (list, float, int): Levels to be read, overriding default in catalog source (only for FDB) .\n            startdate (str): The starting date for reading/streaming the data (e.g. \'2020-02-25\'). Defaults to None.\n            enddate (str): The final date for reading/streaming the data (e.g. \'2020-03-25\'). Defaults to None.\n            history (bool): If you want to add to the metadata history information about retrieve. Defaults to True.\n            sample (bool): read only one default variable (used only if var is not specified). Defaults to False.\n\n        Returns:\n            A xarray.Dataset containing the required data.\n        """\n\n        if not startdate:  # In case the streaming startdate is used also for FDB copy it\n            startdate = self.startdate\n        if not enddate:  # In case the streaming startdate is used also for FDB copy it\n            enddate = self.enddate\n\n        # get loadvar\n        if var:\n            if isinstance(var, str) or isinstance(var, int):\n                var = str(var).split()  # conversion to list guarantees that a Dataset is produced\n            self.logger.info("Retrieving variables: %s", var)\n            # HACK: to be checked if can be done in a better way\n            loadvar = self.fixer.get_fixer_varname(var) if self.fix else var\n        else:\n            # If we are retrieving from fdb we have to specify the var\n            if isinstance(self.esmcat, aqua.gsv.intake_gsv.GSVSource):\n\n                metadata = self.esmcat.metadata\n                if metadata:\n                    loadvar = metadata.get(\'variables\')\n\n                    if loadvar is None:\n                        loadvar = [self.esmcat._request[\'param\']]  # retrieve var from catalog\n\n                    if not isinstance(loadvar, list):\n                        loadvar = [loadvar]\n\n                    if sample:\n                        # self.logger.debug("FDB source sample reading, selecting only one variable")\n                        loadvar = [loadvar[0]]\n\n                    self.logger.debug("FDB source: loading variables as %s", loadvar)\n\n            else:\n                loadvar = None\n\n        ffdb = False\n        # If this is an ESM-intake catalog use first dictionary value,\n        if isinstance(self.esmcat, intake_esm.core.esm_datastore):\n            data = self.reader_esm(self.esmcat, loadvar)\n        # If this is an fdb entry\n        elif isinstance(self.esmcat, aqua.gsv.intake_gsv.GSVSource):\n            data = self.reader_fdb(self.esmcat, loadvar, startdate, enddate,\n                                   dask=True, level=level)\n            ffdb = True  # These data have been read from fdb\n        else:\n            data = self.reader_intake(self.esmcat, var, loadvar)\n\n        # if retrieve history is required (disable for retrieve_plain)\n        if history:\n            if ffdb:\n                fkind = "FDB"\n            else:\n                fkind = "file from disk"\n            data = log_history(data, f"Retrieved from {self.model}_{self.exp}_{self.source} using {fkind}")\n\n\n        if not ffdb:  # FDB sources already have the index, already selected levels\n            data = self._add_index(data)  # add helper index\n            data = self._select_level(data, level=level)  # select levels (optional)\n\n        if self.fix:\n            data = self.fixer.fixer(data, var)\n\n        # log an error if some variables have no units\n        if isinstance(data, xr.Dataset) and self.fix:\n            for variable in data.data_vars:\n                if not hasattr(data[variable], \'units\'):\n                    self.logger.warning(\'Variable %s has no units!\', variable)\n\n        if self.streaming:\n            data = self.streamer.stream(data)\n        else:\n            if data is None or len(data.data_vars) == 0:\n                raise NoDataError("Retrieved empty dataset. Check varname used as first step.")\n\n            if startdate and enddate and not ffdb:  # do not select if data come from FDB (already done)\n                data = data.sel(time=slice(startdate, enddate))\n\n        if isinstance(data, xr.Dataset):\n            data.aqua.set_default(self)  # This links the dataset accessor to this instance of the Reader class\n\n        # Preprocessing function\n        if self.preproc:\n            data = self.preproc(data)\n\n        # Add info metadata in each dataset\n        info_metadata = {\'AQUA_model\': self.model, \'AQUA_exp\': self.exp,\n                         \'AQUA_source\': self.source, \'AQUA_catalog\': self.catalog,\n                         \'AQUA_version\': aqua_version}\n        data = set_attrs(data, info_metadata)\n        \n        return data\n\n    def _add_index(self, data):\n\n        """\n        Add a helper idx_{dim3d} coordinate to the data to be used for level selection\n\n        Arguments:\n            data (xr.Dataset):  the input xarray.Dataset\n\n        Returns:\n            A xarray.Dataset containing the data with the idx_dim{3d} coordinate.\n        """\n\n        if self.vert_coord:\n            for dim in to_list(self.vert_coord):\n                if dim in data.coords:\n                    idx = list(range(0, len(data.coords[dim])))\n                    data = data.assign_coords(**{f"idx_{dim}": (dim, idx)})\n        return data\n\n    def _select_level(self, data, level=None):\n        """\n        Select levels if provided. It is based on self.vert_coord but it extends the feature \n        to atmospheric levels, so it should not be considered as the same vertical coordinate\n\n        Arguments:\n            data (xr.Dataset):  the input xarray.Dataset\n            level (list, int):  levels to be selected. Defaults to None.\n\n        Returns:\n            A xarray.Dataset containing the data with the selected levels.\n        """\n\n        # return if no levels are selected\n        if not level:\n            return data\n\n        # find the vertical coordinate, which can be the smmregrid one or \n        # any other with a dimension compatible (Pa, cm, etc)\n        full_vert_coord = find_vert_coord(data) if not self.vert_coord else self.vert_coord\n\n        # return if no vertical coordinate is found\n        if not full_vert_coord:\n            self.logger.error("Levels selected but no vertical coordinate found in data!")\n            return data\n        \n        # ensure that level is a list\n        level = to_list(level)\n\n        # do the selection on the first vertical coordinate found\n        if len(full_vert_coord) > 1:\n            self.logger.warning(\n                "Found more than one vertical coordinate, using the first one: %s", \n                full_vert_coord[0])\n        data = data.sel(**{full_vert_coord[0]: level})\n        data = log_history(data, f"Selecting levels {level} from vertical coordinate {full_vert_coord[0]}")\n        return data\n    \n    def fldmean(self, data, lon_limits=None, lat_limits=None, **kwargs):\n        """Fldmean average on the data. If regridded, it will use the target grid areas."""\n\n        if self._check_if_regridded(data):\n            return self.tgt_fldstat.fldmean(data, lon_limits=lon_limits, lat_limits=lat_limits, **kwargs)\n        return self.src_fldstat.fldmean(data, lon_limits=lon_limits, lat_limits=lat_limits, **kwargs)\n\n    def set_default(self):\n        """Sets this reader as the default for the accessor."""\n\n        Reader.instance = self  # Refresh the latest reader instance used\n\n    def regrid(self, data):\n        """Call the regridder function returning container or iterator"""\n\n        if self.tgt_grid_name is None:\n            raise NoRegridError(\'regrid has not been initialized in the Reader, cannot perform any regrid.\')\n        \n        data = counter_reverse_coordinate(data)\n\n        out = self.regridder.regrid(data)\n\n        # set regridded attribute to 1 for all vars\n        out = set_attrs(out, {"AQUA_regridded": 1})\n        return out\n    \n    # def trend(self, data, dim=\'time\', degree=1, skipna=False):\n    #     """\n    #     Estimate the trend of an xarray object using polynomial fitting.\n\n    #     Args:\n    #         data (DataArray or Dataset): The input data.\n    #         dim (str): Dimension to apply trend along. Defaults to \'time\'.\n    #         degree (int): Degree of the polynomial. Defaults to 1.\n    #         skipna (bool): Whether to skip NaNs. Defaults to False.\n\n    #     Returns:\n    #         DataArray or Dataset: The trend component.\n    #     """\n    #     final = self.trender.trend(data, dim=dim, degree=degree, skipna=skipna)\n    #     final.aqua.set_default(self)\n    #     return final\n\n    def detrend(self, data, dim=\'time\', degree=1, skipna=False):    \n        """\n        Remove the trend from an xarray object using polynomial fitting.\n\n        Args:\n            data (DataArray or Dataset): The input data.\n            dim (str): Dimension to apply detrend along. Defaults to \'time\'.\n            degree (int): Degree of the polynomial. Defaults to 1.\n            skipna (bool): Whether to skip NaNs. Defaults to False.\n\n        Returns:\n            DataArray or Dataset: The detrended data.\n        """\n        final = self.trender.detrend(data, dim=dim, degree=degree, skipna=skipna)\n        final.aqua.set_default(self)\n        return final\n\n    def _check_if_regridded(self, data):\n        """\n        Checks if a dataset or Datarray has been regridded.\n\n        Arguments:\n            data (xr.DataArray or xarray.DataDataset):  the input data\n        Returns:\n            A boolean value\n        """\n\n        if isinstance(data, xr.Dataset):\n            att = list(data.data_vars.values())[0].attrs\n        else:\n            att = data.attrs\n\n        return att.get("AQUA_regridded", False)\n\n    # def _clean_spourious_coords(self, data, name=None):\n    #     """\n    #     Remove spurious coordinates from an xarray DataArray or Dataset.\n\n    #     This function identifies and removes unnecessary coordinates that may\n    #     be incorrectly associated with spatial coordinates, such as a time\n    #     coordinate being linked to latitude or longitude.\n\n    #     Parameters:\n    #     ----------\n    #     data : xarray.DataArray or xarray.Dataset\n    #         The input data object from which spurious coordinates will be removed.\n\n    #     name : str, optional\n    #         An optional name or identifier for the data. This will be used in\n    #         warning messages to indicate which dataset the issue pertains to.\n\n    #     Returns:\n    #     -------\n    #     xarray.DataArray or xarray.Dataset\n    #         The cleaned data object with spurious coordinates removed.\n    #     """\n\n    #     drop_coords = set()\n    #     for coord in list(data.coords):\n    #         if len(data[coord].coords)>1:\n    #             drop_coords.update(koord for koord in data[coord].coords if koord != coord)\n    #     if not drop_coords:\n    #         return data\n    #     self.logger.warning(\'Issue found in %s, removing %s coordinates\',\n    #                             name, list(drop_coords))\n    #     return data.drop_vars(drop_coords)\n\n    def _filter_kwargs(self, intake_vars: dict={}, kwargs: dict={}, engine: str = \'fdb\'):\n        """\n        Uses the esmcat.describe() to remove the intake_vars, then check in the parameters if the kwargs are present.\n        Kwargs which are not present in the intake_vars will be removed.\n\n        Args:\n            intake_vars (dict): The intake variables from the catalog machine specific file.\n            kwargs (dict): The keyword arguments passed to the reader, which are intake parameters in the source.\n            engine (str): The engine used for the GSV retrieval, default is \'fdb\'.\n\n        Returns:\n            A dictionary of kwargs filtered to only include parameters that are present in the intake_vars.\n        """\n        esm_dict = self.esmcat.describe().get(\'user_parameters\', {})\n        len_esmcat = len(esm_dict)\n\n        # This contains both the intake_vars and the esmcat parameters\n        params = [esm_dict[i][\'name\'] for i in range(len_esmcat)]\n\n        # List comprehension to filter out kwargs that are not in the params\n        filtered_kwargs = {k: v for k, v in kwargs.items() if k in params}\n        unfiltered_kwargs = {k: v for k, v in kwargs.items() if k not in params}\n\n        # Log warnings for unfiltered kwargs\n        for key, _ in unfiltered_kwargs.items():\n            self.logger.warning(\'kwarg %s is not in the intake parameteres of the source, removing it\', key)\n\n        # Check if all required parameters are present in the filtered kwargs and set defaults if not\n        filtered_list = list(filtered_kwargs.keys())\n        intake_vars_list = list(intake_vars.keys())\n        for param in params:\n            if param not in filtered_list and param not in intake_vars_list:\n                self.logger.warning(\'%s parameter is required but is missing, setting to default %s\',\n                                    param, esm_dict[params.index(param)][\'default\'])\n                allowed = esm_dict[params.index(param)].get(\'allowed\', None)\n                # It is possible to have intake_vars which are not specified for the machine,\n                # so that we still need to check whether there is an allowed list\n                if allowed is not None:\n                    self.logger.warning(\'Available values for %s are: %s\', param, allowed)\n                filtered_kwargs[param] = esm_dict[params.index(param)][\'default\']\n\n        if isinstance(self.esmcat, aqua.gsv.intake_gsv.GSVSource):\n            # If the engine is fdb, we need to add the engine parameter\n            if \'engine\' not in filtered_kwargs:\n                filtered_kwargs[\'engine\'] = engine\n                self.logger.debug(\'Adding engine=%s to the filtered kwargs\', engine)\n\n        return filtered_kwargs\n\n    def vertinterp(self, data, levels=None, vert_coord=\'plev\', units=None,\n                   method=\'linear\'):\n        """\n        A basic vertical interpolation based on interp function\n        of xarray within AQUA. Given an xarray object, will interpolate the\n        vertical dimension along the vert_coord.\n        If it is a Dataset, only variables with the required vertical\n        coordinate will be interpolated.\n\n        Args:\n            data (DataArray, Dataset): your dataset\n            levels (float, or list): The level you want to interpolate the vertical coordinate\n            units (str, optional, ): The units of your vertical axis. Default \'Pa\'\n            vert_coord (str, optional): The name of the vertical coordinate. Default \'plev\'\n            method (str, optional): The type of interpolation method supported by interp()\n\n        Return\n            A DataArray or a Dataset with the new interpolated vertical dimension\n        """\n\n        if levels is None:\n            raise KeyError(\'Levels for interpolation must be specified\')\n\n        # error if vert_coord is not there\n        if vert_coord not in data.coords:\n            raise KeyError(f\'The vert_coord={vert_coord} is not in the data!\')\n\n        # if you not specified the units, guessing from the data\n        if units is None:\n            if hasattr(data[vert_coord], \'units\'):\n                self.logger.warning(\'Units of vert_coord=%s has not defined, reading from the data\', vert_coord)\n                units = data[vert_coord].units\n            else:\n                raise ValueError(\'Original dataset has not unit on the vertical axis, failing!\')\n\n        if isinstance(data, xr.DataArray):\n            final = self._vertinterp(data=data, levels=levels, units=units,\n                                     vert_coord=vert_coord, method=method)\n\n        elif isinstance(data, xr.Dataset):\n            selected_vars = [da for da in data.data_vars if vert_coord in data[da].coords]\n            final = data[selected_vars].map(self._vertinterp, keep_attrs=True,\n                                            levels=levels, units=units,\n                                            vert_coord=vert_coord, method=method)\n        else:\n            raise ValueError(\'This is not an xarray object!\')\n\n        final = log_history(\n            final, f"Interpolated from original levels {data[vert_coord].values} {data[vert_coord].units} to level {levels} using {method} method.") # noqa E501\n\n        final.aqua.set_default(self)  # This links the dataset accessor to this instance of the Reader class\n\n        return final\n\n    def _vertinterp(self, data, levels=None, units=\'Pa\', vert_coord=\'plev\', method=\'linear\'):\n\n        # verify units are good\n        if data[vert_coord].units != units:\n            self.logger.warning(\'Converting vert_coord units to interpolate from %s to %s\',\n                                data[vert_coord].units, units)\n            data = data.metpy.convert_coordinate_units(vert_coord, units)\n\n        # very simple interpolation\n        final = data.interp({vert_coord: levels}, method=method)\n\n        return final\n\n\n    def reader_esm(self, esmcat, var):\n        """Reads intake-esm entry. Returns a dataset."""\n        cdf_kwargs = esmcat.metadata.get(\'cdf_kwargs\', {"chunks": {"time": 1}})\n        query = esmcat.metadata[\'query\']\n        if var:\n            query_var = esmcat.metadata.get(\'query_var\', \'short_name\')\n            # Convert to list if not already\n            query[query_var] = var.split() if isinstance(var, str) else var\n        subcat = esmcat.search(**query)\n        data = subcat.to_dataset_dict(cdf_kwargs=cdf_kwargs,\n                                      # zarr_kwargs=dict(consolidated=True),\n                                      # decode_times=True,\n                                      # use_cftime=True)\n                                      progressbar=False\n                                      )\n        return list(data.values())[0]\n\n    def reader_fdb(self, esmcat, var, startdate, enddate, dask=False, level=None):\n        """\n        Read fdb data. Returns a dask array.\n\n        Args:\n            esmcat (intake catalog): the intake catalog to read\n            var (str, int or list): the variable(s) to read\n            startdate (str): a starting date and time in the format YYYYMMDD:HHTT\n            enddate (str): an ending date and time in the format YYYYMMDD:HHTT\n            dask (bool): return directly a dask array\n            level (list, float, int): level to be read, overriding default in catalog\n\n        Returns:\n            An xarray.Dataset \n        """\n        # Var can be a list or a single one of these cases:\n        # - an int, in which case it is a paramid\n        # - a str, in which case it is a short_name that needs to be matched with the paramid\n        # - a list (in this case I may have a list of lists) if fix=True and the original variable\n        #   found a match in the source field of the fixer dictionary\n        request = esmcat._request\n        var = to_list(var)\n        var_match = []\n\n        fdb_var = esmcat.metadata.get(\'variables\', None)\n        # This is a fallback for the case in which no \'variables\' metadata is defined\n        # It is a backward compatibility feature and it may be removed in the future\n        # We need to access with describe because the \'param\' element is not a class\n        # attribute. I would not add it since it is a deprecated feature\n        if fdb_var is None:\n            self.logger.warning("No \'variables\' metadata defined in the catalog, this is deprecated!")\n            fdb_var = esmcat.describe()["args"]["request"]["param"]\n            fdb_var = to_list(fdb_var)\n\n        # We avoid the following loop if the user didn\'t specify any variable\n        # We make sure this is the case by checking that var is the same as fdb_var\n        # If we need to loop, two cases may arise:\n        # 1. fix=True: if elem is a paramid we try to match it with the list on fdb_var\n        #              if is a str we scan in the fixer dictionary if there is a match\n        #              and we use the paramid listed in the source block to match with fdb_var\n        #              As a final fallback, if the scan fails, we use the initial str as a match\n        #              letting eccodes itself to find the paramid (this may lead to errors)\n        # 2. fix=False: we just scan the list of variables requested by the user.\n        #               For paramids we do as case 1, while for str we just do as in the fallback\n        #               option defined in case 1\n        # We\'re trying to set the if/else by int vs str and then eventually by the fix option\n        # We store the fixer_dict once for all for semplicity of the if case.\n        if self.fix is True:\n            fixer_dict = self.fixer.fixes.get(\'vars\', {})\n            if fixer_dict == {}:\n                self.logger.debug("No \'vars\' block in the fixer, guessing variable names base on ecCodes")\n        if var != fdb_var:\n            for element in var:\n                # We catch also the case where we ask for var=\'137\' but we know that is a paramid\n                if isinstance(element, int) or (isinstance(element, str) and element.isdigit()):\n                    element = int(element) if isinstance(element, str) else element\n                    element = to_list(element)\n                    match = list(set(fdb_var) & set(element))\n                    if match and len(match) == 1:\n                        var_match.append(match[0])\n                    elif match and len(match) > 1:\n                        self.logger.warning(\'Multiple matches found for %s, using the first one\', element)\n                        var_match.append(match[0])\n                    else:\n                        self.logger.warning(\'No match found for %s, skipping it\', element)\n                elif isinstance(element, str):\n                    if self.fix is True:\n                        if element in fixer_dict:\n                            src_element = fixer_dict[element].get(\'source\', None)\n                            derived_element = fixer_dict[element].get(\'derived\', None)\n                            if derived_element is not None or src_element is None:  # We let eccodes to find the paramid\n                                var_match.append(derived_element)\n                            else:  # src_element is not None and it is not a derived variable\n                                match = list(set(fdb_var) & set(src_element))\n                                if match and len(match) == 1:\n                                    var_match.append(match[0])\n                                elif match and len(match) > 1:\n                                    self.logger.warning(\'Multiple paramids found for %s: %s, using: %s\',\n                                                        element, match, match[0])\n                                    var_match.append(match[0])\n                                else:\n                                    self.logger.warning(\'No match found for %s, using eccodes to find the paramid\',\n                                                        element)\n                                    var_match.append(element)\n                    else:\n                        var_match.append(element)\n                elif isinstance(element, list):\n                    if self.fix is False:\n                        raise ValueError(f"Var {element} is a list and fix is False, this is not allowed")\n                    match = list(set(fdb_var) & set(element))\n                    if match and len(match) == 1:\n                        var_match.append(match[0])\n                    elif match and len(match) > 1:\n                        self.logger.warning(\'Multiple matches found for %s, using the first one\', element)\n                        var_match.append(match[0])\n                    else:\n                        self.logger.error(\'No match found for %s, skipping it\', element)\n                else:  # Something weird is happening, we may want to have a raise instead\n                    self.logger.error("Element %s is not a valid type, skipping it", element)\n        else:  # There is no need to scan the list of variables, total match\n            var_match = var\n\n        if var_match == []:\n            self.logger.error("No match found for the variables you are asking for!")\n            self.logger.error("Please be sure the metadata \'variables\' is defined in the catalog")\n            var_match = var\n        else:\n            self.logger.debug("Found variables: %s", var_match)\n\n        var = var_match\n        self.logger.debug("Requesting variables: %s", var)\n\n        if level and not isinstance(level, list):\n            level = [level]\n\n        # for streaming emulator\n        if self.aggregation and not dask:\n            chunks = self.aggregation\n        else:\n            chunks = self.chunks\n\n        if isinstance(chunks, dict):\n            if self.aggregation and not chunks.get(\'time\'):\n                chunks[\'time\'] = self.aggregation\n            if self.streaming and not self.aggregation:\n                self.logger.warning(\n                    "Aggregation is not set, using default time resolution for streaming. If you are asking for a longer chunks[\'time\'] for GSV access, please set a suitable aggregation value") # noqa E501\n\n        if dask:\n            if chunks:  # if the chunking or aggregation option is specified override that from the catalog\n                data = esmcat(request=request, startdate=startdate, enddate=enddate, var=var, level=level,\n                              chunks=chunks, logging=True, loglevel=self.loglevel).to_dask()\n            else:\n                data = esmcat(request=request, startdate=startdate, enddate=enddate, var=var, level=level,\n                              logging=True, loglevel=self.loglevel).to_dask()\n        else:\n            if chunks:\n                data = esmcat(request=request, startdate=startdate, enddate=enddate, var=var, level=level,\n                              chunks=chunks, logging=True, loglevel=self.loglevel).read_chunked()\n            else:\n                data = esmcat(request=request, startdate=startdate, enddate=enddate, var=var, level=level,\n                              logging=True, loglevel=self.loglevel).read_chunked()\n\n        return data\n\n    def reader_intake(self, esmcat, var, loadvar, keep="first"):\n        """\n        Read regular intake entry. Returns dataset.\n\n        Args:\n            esmcat (intake.catalog.Catalog): your catalog\n            var (list or str): Variable to load\n            loadvar (list of str): List of variables to load\n            keep (str, optional): which duplicate entry to keep ("first" (default), "last" or None)\n\n        Returns:\n            Dataset\n        """\n        # The coder introduces the possibility to specify a time decoder for the time axis\n        if \'time_coder\' in esmcat.metadata:\n            coder = xr.coders.CFDatetimeCoder(time_unit=esmcat.metadata[\'time_coder\'])\n            esmcat.xarray_kwargs.update({\'decode_times\': coder})\n\n        data = esmcat.to_dask()\n\n        if loadvar:\n            loadvar = to_list(loadvar)\n            loadvar_match = []\n            for element in loadvar:\n                # Having to do a list comprehension we want to be sure that the element is a list\n                element = to_list(element)\n                match = list(set(data.data_vars) & set(element))\n\n                if match:\n                    loadvar_match.append(match[0])\n                else:\n                    self.logger.warning(\'No match found for %s\', element)\n            loadvar = loadvar_match\n\n            if all(element in data.data_vars for element in loadvar):\n                data = data[loadvar]\n            else:\n                try:\n                    data = data[var]\n                    self.logger.warning("You are asking for var %s but the fixes definition requires %s, which is not there.",\n                                        var, loadvar)\n                    self.logger.warning("Retrieving %s, but it would be safer to run with fix=False or to correct the fixes",\n                                        var)\n                except Exception as e:\n                    raise KeyError("You are asking for variables which we cannot find in the catalog!") from e\n\n        # check for duplicates\n        if \'time\' in data.coords:\n            len0 = len(data.time)\n            data = data.drop_duplicates(dim=\'time\', keep=keep)\n            if len(data.time) != len0:\n                self.logger.warning("Duplicate entries found along the time axis, keeping the %s one.", keep)\n\n        return data\n\n    @contextmanager\n    def _temporary_attrs(self, **kwargs):\n        """Temporarily override Reader attributes, restoring them afterward."""\n        original_values = {key: getattr(self, key) for key in kwargs}\n        try:\n            for key, value in kwargs.items():\n                setattr(self, key, value)\n            yield\n        finally:\n            for key, value in original_values.items():\n                setattr(self, key, value)\n\n    def _retrieve_plain(self, *args, **kwargs):\n        """\n        Retrieve data without any additional processing.\n        Making use of GridInspector, provide a sample data which has minimum\n        size by subselecting along variables and time dimensions \n\n        Args:\n            *args: arguments to be passed to retrieve\n            **kwargs: keyword arguments to be passed to retrieve\n\n        Returns:\n            A xarray.Dataset containing the required miminal sample data.\n        """\n        if self.sample_data is not None:\n            self.logger.debug(\'Sample data already availabe, avoid _retrieve_plain()\')\n            return self.sample_data\n\n        # Temporarily disable unwanted settings\n        with self._temporary_attrs(aggregation=None, chunks=None, fix=False, streaming=False,\n                                   startdate=None, enddate=None, preproc=None):\n            self.logger.debug(\'Getting sample data through _retrieve_plain()...\')\n            data = self.retrieve(history=False, *args, **kwargs)\n\n        self.sample_data = self._grid_inspector(data)\n        return self.sample_data\n\n    def _grid_inspector(self, data):\n        """\n        Use smmregrid GridInspector to get minimal sample data\n\n        Args:\n            data (xarray.Dataset): input data\n\n        Returns:\n            A xarray.Dataset containing the required miminal sample data.\n        """\n\n        # get gridtypes from smrregird\n        gridinspect = GridInspector(data, loglevel=self.loglevel)\n        gridtypes = gridinspect.get_gridtype()\n\n        # get info on time dimensions and variables\n        minimal_variables = gridinspect.get_gridtype_attr(gridtypes, \'variables\')\n        minimal_time = gridinspect.get_gridtype_attr(gridtypes, \'time_dims\')\n\n        if minimal_variables:\n            self.logger.debug(\'Variables found: %s\', minimal_variables)\n            data = data[minimal_variables]\n        if minimal_time:\n            self.logger.debug(\'Time dimensions found: %s\', minimal_time)\n            data = data.isel({t: 0 for t in minimal_time})\n        return data\n\n    def timstat(self, data, stat, freq=None, exclude_incomplete=False,\n             time_bounds=False, center_time=False):\n        """\n        Time averaging wrapper which is calling the timstat module\n\n        Args:\n            data (xr.DataArray or xarray.Dataset):  the input data\n            stat (str):  the statistical function to be applied\n            freq (str):  the frequency of the time average\n            exclude_incomplete (bool):  exclude incomplete time averages\n            time_bounds (bool):  produce time bounds after averaging\n            center_time (bool):  center time for averaging\n        """\n\n        data = self.timemodule.timstat(\n            data, stat=stat, freq=freq,\n            exclude_incomplete=exclude_incomplete,\n            time_bounds=time_bounds,\n            center_time=center_time)\n        data.aqua.set_default(self) #accessor linking\n        return data\n    \n    def timmean(self, data, **kwargs):\n        return self.timstat(data, stat=\'mean\', **kwargs)\n\n    def timmax(self, data, **kwargs):\n        return self.timstat(data, stat=\'max\', **kwargs)\n    \n    def timmin(self, data, **kwargs):\n       return self.timstat(data, stat=\'min\', **kwargs)\n    \n    def timstd(self, data, **kwargs):\n       return self.timstat(data, stat=\'std\', **kwargs)\n    \n    def timsum(self, data, **kwargs):\n       return self.timstat(data, stat=\'sum\', **kwargs)\n\n    def histogram(self, data, **kwargs):\n        """ Wrapper for the histogram function. """\n\n        return histogram(data, **kwargs)\n\n\ndef units_extra_definition():\n    """Add units to the pint registry"""\n\n    # special units definition\n    # needed to work with metpy 1.4.0 see\n    # https://github.com/Unidata/MetPy/issues/2884\n    units._on_redefinition = \'ignore\'\n    units.define(\'fraction = [] = Fraction = frac\')\n    units.define(\'psu = 1e-3 frac\')\n    units.define(\'PSU = 1e-3 frac\')\n    units.define(\'Sv = 1e+6 m^3/s\')\n    units.define("North = degrees_north = degreesN = degN")\n    units.define("East = degrees_east = degreesE = degE")\n',
            'tests/seaice/test_seaice.py': 'import pytest \nimport xarray as xr\nfrom aqua.diagnostics import SeaIce\nfrom aqua.exceptions import NoDataError\n\n# pytest approximation, to bear with different machines\napprox_rel = 1e-4\nabs_rel = 1e-4\nloglevel = \'DEBUG\'\n\ncatalog = \'ci\'\nmodel = \'FESOM\'\nexp = \'hpz3\'\nsource = \'monthly-2d\'\n\n@pytest.mark.diagnostics\nclass TestSeaIce:\n    """Test the SeaIce class."""\n    \n    @pytest.mark.parametrize(\n        (\'method\', \'region\', \'value\', \'expected_units\', \'variable\', \'calc_std_freq\', \'expect_exception\', \'error_message\'),\n        [\n        # Valid cases without standard deviation\n        (\'extent\', \'arctic\',     17.2719, \'million km^2\',   \'siconc\', None, None, None),\n        (\'extent\', \'weddell_sea\', 4.5872, \'million km^2\',   \'siconc\', None, None, None),\n        (\'volume\', \'arctic\',     13.7552, \'thousands km^3\', \'siconc\', None, None, None),\n        (\'volume\', \'antarctic\',   9.1140, \'thousands km^3\', \'siconc\', None, None, None),\n\n        # Valid cases with standard deviation computation\n        (\'extent\', \'arctic\',    3.9402, \'million km^2\',   \'siconc\', \'annual\',  None, None),\n        (\'extent\', \'antarctic\', 0.7623, \'million km^2\',   \'siconc\', \'monthly\', None, None),\n        (\'volume\', \'antarctic\', 1.003,  \'thousands km^3\', \'siconc\', \'monthly\', None, None),\n\n        # Invalid cases (Errors expected)\n        (\'wrong_method\', \'antarctic\',   None, None, \'siconc\',   None, ValueError, "Invalid method"),\n        (\'extent\',       \'weddell_sea\', None, None, \'errorvar\', None, (KeyError, NoDataError),   None),\n        (\'volume\',       \'antarctic\',   None, None, \'errorvar\', None, (KeyError, NoDataError),   None),\n\n        # Invalid standard deviation cases\n        (\'extent\', \'weddell_sea\', None, None, \'errorvar\', None, (KeyError, NoDataError), None),\n        (\'volume\', \'antarctic\',   None, None, \'errorvar\', None, (KeyError, NoDataError), None)\n        ]\n    )\n    def test_seaice_compute_with_std(self, method, region, value, expected_units, variable,\n                                     calc_std_freq, expect_exception, error_message):\n        """Test sea ice computation including std for both valid and invalid cases."""\n\n        seaice = SeaIce(catalog=catalog, model=model, exp=exp, source=source, \n                        startdate="1991-01-01", enddate="2000-01-01", regions=region, regrid=\'r100\', loglevel=loglevel)\n\n        # Handle expected exceptions first\n        if expect_exception:\n            with pytest.raises(expect_exception, match=error_message if error_message else ""):\n                seaice.compute_seaice(method=method, var=variable, calc_std_freq=calc_std_freq)\n            return\n\n        # Valid case: compute sea ice with or without standard deviation result is a Tuple if calc_std_freq is not None\n        result = seaice.compute_seaice(method=method, var=variable, calc_std_freq=calc_std_freq)\n\n        if calc_std_freq:\n\n            assert isinstance(result, tuple)\n            assert len(result) == 2\n\n            # unpack the tuple \n            res, res_std = result\n\n            assert isinstance(res, xr.Dataset)\n            assert isinstance(res_std, xr.Dataset)\n\n            regionlower = region.lower().replace(" ", "_")\n            var_name = f\'sea_ice_{method}_{regionlower}\'\n            std_var_name = f\'std_sea_ice_{method}_{regionlower}\'\n\n            assert all(c in [\'variable\', \'time\'] for c in res.coords)\n            assert list(res.data_vars) == [var_name]\n            assert res.attrs[\'units\'] == expected_units\n\n            # Adjusted assertion for time coordinate\n            expected_time_coord = "year" if calc_std_freq == "annual" else "month" if calc_std_freq == "monthly" else "time"\n            assert expected_time_coord in res_std.coords\n\n            assert list(res_std.data_vars) == [std_var_name]\n            assert res_std.attrs[\'units\'] == expected_units  # Std should retain units\n\n        else:\n            # If no std computation, result should be a single Dataset\n            assert isinstance(result, xr.Dataset)\n            regionlower = region.lower().replace(" ", "_")\n            var_name = f\'sea_ice_{method}_{regionlower}\'\n            \n            assert all(c in [\'variable\', \'time\'] for c in result.coords)\n            assert list(result.data_vars) == [var_name]\n            assert result.attrs[\'units\'] == expected_units\n            assert result[var_name].values[5] == pytest.approx(value, rel=approx_rel)\n\n    @pytest.mark.parametrize(\n        (\'method\', \'region\', \'variable\', \'value\', \'kwargs\', \'expected_coords\'),\n        [\n        (\'extent\', \'arctic\',    \'siconc\', 21.4141, {\'calc_std_freq\': \'monthly\', \'get_seasonal_cycle\': True}, [\'variable\', \'month\']),\n        (\'extent\', \'antarctic\', \'siconc\',  3.2294, {\'calc_std_freq\': \'monthly\', \'get_seasonal_cycle\': True}, [\'variable\', \'month\']),\n        ]\n    )\n    def test_get_seasonal_cycle_with_region(self, method, region, variable, value, kwargs, expected_coords):\n        """Test the get_seasonal_cycle functionality with region as a parameter."""\n\n        seaice = SeaIce(catalog=catalog, model=model, exp=exp, source=source,\n                        startdate="1991-01-01", enddate="2000-01-01", regions=region, \n                        regrid=\'r100\', loglevel=loglevel)\n\n        result, result_std = seaice.compute_seaice(method=method, var=variable, **kwargs)\n\n        # Assertions for the seasonal cycle\n        assert isinstance(result, xr.Dataset)\n        assert isinstance(result_std, xr.Dataset)\n        assert list(result.coords) == expected_coords\n        assert list(result_std.coords) == expected_coords\n\n        regionlower = region.lower().replace(" ", "_")\n        var_name = f\'sea_ice_{method}_{regionlower}\'\n        assert result[var_name].values[0] == pytest.approx(value, rel=approx_rel)\n\n    ################## TO be implemented ###################\n    @pytest.mark.parametrize(\n        (\'method\', \'region\',  \'value\', \'variable\', \'expect_exception\'),\n        [\n        # Valid cases without standard deviation\n        (\'fraction\',  \'arctic\',    0.2817,  \'siconc\',   None),\n        (\'thickness\', \'antarctic\', 0.0619,  \'sithick\',  None),\n\n        # Invalid cases (Errors expected)\n        (\'fraction\',[1,2,3], None, \'siconc\', ValueError),\n        # (\'wrong_method\', \'antarctic\',   None, None, \'siconc\',   None, ValueError, "Invalid method"),\n        # (\'fraction\',     \'weddell_sea\', None, None, \'errorvar\', None, KeyError, None),\n        # (\'thickness\',    \'antarctic\',   None, None, \'errorvar\', None, KeyError, None),\n\n        # # Invalid standard deviation cases\n        # (\'extent\', \'weddell_sea\', None, None, \'errorvar\', None, KeyError, None),\n        # (\'volume\', \'antarctic\',   None, None, \'errorvar\', None, KeyError, None)\n        ]\n    )\n    def test_seaice_2d_monthly_climatology(self, method, region, value, variable, expect_exception):\n        """Test sea ice computation for 2D monthly climatology including std for both valid and invalid cases."""\n\n        def create_seaice():\n            return SeaIce(catalog=catalog, model=model, exp=exp, source=source,\n                startdate="1991-01-01", enddate="2000-01-01", regions=region,\n                regrid=\'r100\', loglevel=loglevel)\n\n        # Handle expected exceptions first\n        if expect_exception:\n            with pytest.raises(expect_exception):\n                seaice = create_seaice()\n                seaice.compute_seaice(method=method, var=variable)\n            return\n        else:\n            seaice = create_seaice()\n        \n        # Valid case: compute sea ice\n        result = seaice.compute_seaice(method=method, var=variable)\n\n        assert isinstance(result, xr.Dataset)\n\n        # Get the specific variable from the dataset\n        regionlower = region.lower().replace(" ", "_")\n        var_name = f\'sea_ice_{method}_{regionlower}\'\n        result_data = result[var_name]\n\n        assert isinstance(result_data, xr.DataArray)\n\n        meanres = result_data.mean(skipna=True).values\n\n        assert meanres == pytest.approx(value, rel=approx_rel, abs=abs_rel)\n\n\n\n\n',
            'tests/test_basic.py': 'import pytest\nimport numpy as np\nfrom aqua import Reader, catalog\n\n# pytest approximation, to bear with different machines\napprox_rel = 1e-4\nloglevel = "DEBUG"\n\n@pytest.fixture\ndef reader_instance():\n    return Reader(model="FESOM", exp="test-pi", source="original_2d",\n                  regrid="r200", fix=False, loglevel=loglevel)\n\n# aqua class for tests\n@pytest.mark.aqua\nclass TestAqua:\n    """Basic tests for AQUA"""\n\n    @pytest.mark.parametrize("module_name", ["aqua", "aqua.diagnostics"])\n    def test_aqua_import(self, module_name):\n        """\n        Test if the aqua module is imported correctly\n        """\n        try:\n            __import__(module_name)\n        except ImportError:\n            assert False, "Module {} could not be imported".format(module_name)\n\n    def test_aqua_catalog(self):\n        """\n        Test if the catalog function returns a non-empty list\n        """\n        cat = catalog()\n        assert len(cat) > 0\n\n    def test_reader_init(self):\n        """\n        Test the initialization of the Reader class\n        """\n        reader = Reader(model="FESOM", exp="test-pi", source="original_2d",\n                        fix=False, loglevel=loglevel)\n        assert reader.model == "FESOM"\n        assert reader.exp == "test-pi"\n        assert reader.source == "original_2d"\n\n    def test_retrieve_data(self, reader_instance):\n        """\n        Test if the retrieve method returns data with the expected shape\n        """\n        data = reader_instance.retrieve()\n        assert len(data) > 0\n        assert data.a_ice.shape == (2, 3140)\n        assert data.a_ice.attrs[\'AQUA_catalog\'] == \'ci\'\n        assert data.a_ice.attrs[\'AQUA_model\'] == \'FESOM\'\n        assert data.a_ice.attrs[\'AQUA_exp\'] == \'test-pi\'\n        assert data.a_ice.attrs[\'AQUA_source\'] == \'original_2d\'\n\n    def test_regrid_data(self, reader_instance):\n        """\n        Test if the regrid method returns data with the expected\n        shape and values\n        """\n        data = reader_instance.retrieve()\n        sstr = reader_instance.regrid(data["sst"][0:2, :])\n        assert sstr.shape == (2, 90, 180)\n        assert np.nanmean(sstr[0, :, :].values) == pytest.approx(13.350324258783935, rel=approx_rel)\n        assert np.nanmean(sstr[1, :, :].values) == pytest.approx(13.319154700343551, rel=approx_rel)\n\n    def test_fldmean(self, reader_instance):\n        """\n        Test if the fldmean method returns data with the expected\n        shape and values\n        """\n        data = reader_instance.retrieve()\n        global_mean = reader_instance.fldmean(data.sst[:2, :])\n        assert global_mean.shape == (2,)\n        assert global_mean.values[0] == pytest.approx(17.99434183,\n                                                      rel=approx_rel)\n        assert global_mean.values[1] == pytest.approx(17.98060367,\n                                                      rel=approx_rel)\n\n    def test_catalog_override(self):\n        """\n        Test the compact catalog override functionality\n        """\n        reader = Reader(model="IFS", exp="test-tco79", source="short_override",\n                        loglevel=loglevel)\n        assert reader.esmcat.metadata[\'test-key\'] == "test-value"  # from the default\n        assert reader.src_grid_name == "tco79-nn"  # overwritten key\n\n    def test_empty_dataset_error(self, reader_instance):\n        """\n        Test that NoDataError is raised when empty dataset is retrieved\n        """\n        with pytest.raises(Exception):\n            reader_instance.retrieve(var="nonexistent_variable")\n\n    def test_time_selection_with_dates(self, reader_instance):\n        """\n        Test that time selection is applied when both startdate and enddate are provided\n        """\n        full_data = reader_instance.retrieve()\n\n        if len(full_data.time) < 2:\n            pytest.skip("Not enough timesteps to test")\n        \n        startdate = str(full_data.time[0].values)[:10]\n        enddate = str(full_data.time[-1].values)[:10]\n    \n        selected_data = reader_instance.retrieve(startdate=startdate, enddate=enddate)\n        \n        # Verify time selection was applied\n        assert len(selected_data.time) == len(full_data.time)\n        assert selected_data.time[0].values == full_data.time[0].values\n\n    @pytest.fixture(\n        params=[\n            ("IFS", "test-tco79", "short", "r200", "tas"),\n            ("FESOM", "test-pi", "original_2d", "r200", "sst"),\n            ("NEMO", "test-eORCA1", "long-2d", "r200", "sst")\n        ]\n    )\n    def reader_arguments(self, request):\n        return request.param\n\n    def test_reader_with_different_arguments(self, reader_arguments):\n        """\n        Test if the Reader class works with different combinations of arguments\n        """\n        model, exp, source, regrid, _ = reader_arguments\n        reader = Reader(model=model, exp=exp, source=source, regrid=regrid,\n                        fix=False, loglevel=loglevel)\n        data = reader.retrieve()\n\n        # Check the time precision\n        if model == \'NEMO\':\n            assert data.time.values[0].dtype == \'datetime64[s]\'\n\n        assert len(data) > 0\n',
        }
